//! Semantic reconstruction compiler for binary artifacts.
//!
//! This crate takes observed binary facts plus THIR and emits graph-backed
//! reconstruction obligations. It intentionally does not produce human-facing
//! decompiler text; it produces bounded tasks with evidence and validators.

// The reconstruction lowering code favors per-family clarity over clippy's style
// preferences: each lowering fn takes one slice per Ghidra oracle fact family (a
// struct-bundle would hide the per-family contract), and several passes use
// filter_map for uniformity with sibling filtering lowerings. These are style,
// not correctness; behavior is gated by the tests.
#![allow(clippy::too_many_arguments)]
#![allow(clippy::unnecessary_filter_map)]

use std::collections::{BTreeMap, BTreeSet};

use petgraph::graphmap::DiGraphMap;
use rustyred_thg_binformat::{
    BinaryLoadReport, BinaryString, ProgramCompilerInjectParameter, ProgramCompilerSpec,
    ProgramLanguageSpec,
};
use rustyred_thg_code::{
    GhidraOracleAnnotationFact, GhidraOracleCallStackEffectFact, GhidraOracleDataTypeFact,
    GhidraOracleDataTypeFieldFact, GhidraOracleDecompilerDiagnosticFact, GhidraOracleEquateFact,
    GhidraOracleEquateReferenceFact, GhidraOracleExternalLinkageFact,
    GhidraOracleExternalThunkLinkFact, GhidraOracleFixture, GhidraOracleFunctionIdFact,
    GhidraOracleFunctionPrototypeFact, GhidraOracleFunctionPrototypeParameterFact,
    GhidraOracleHighVariableFact, GhidraOracleHighVariableInstanceFact,
    GhidraOracleJumpTableCaseFact, GhidraOracleJumpTableFact, GhidraOracleJumpTableLoadTableFact,
    GhidraOracleMemoryWitnessFact, GhidraOracleParameterMeasureFact,
    GhidraOracleSemanticSignatureFact, GhidraOracleStackFrameFact,
    GhidraOracleStackFrameVariableFact, GhidraOracleStructureFieldAccessFact,
    GhidraOracleSymbolicModelBinding, GhidraOracleSymbolicPreconditionFact,
    GhidraOracleSymbolicSummaryFact, GhidraOracleSymbolicValueFact,
    GhidraOracleVariableStorageFact, GhidraOracleVariableStoragePieceFact,
};
use rustyred_thg_core::{stable_hash, EdgeRecord, GraphStore, GraphStoreResult, NodeRecord};
use rustyred_thg_lift::{
    lower_thir_to_pcode, PcodeFact, PcodeOpcode, ThirFunction, ThirProgram, ThirStmt,
};
use serde::{Deserialize, Serialize};
use serde_json::{json, Value};

