pub fn tenant_scoped_reconstruction_id(tenant_id: &str, id: &str) -> String {
    let prefix = tenant_id_prefix(tenant_id);
    if id.starts_with(&prefix) {
        id.to_string()
    } else {
        format!("{prefix}{id}")
    }
}

