pub fn pcode_inject_contracts_from_program_language_specs(
    language_specs: &[ProgramLanguageSpec],
) -> Vec<PcodeInjectContract> {
    let mut contracts = language_specs
        .iter()
        .flat_map(|language_spec| {
            pcode_inject_contracts_from_program_compiler_specs(
                &language_spec.artifact_id,
                &language_spec.compiler_specs,
            )
        })
        .collect::<Vec<_>>();
    contracts.sort_by(|left, right| {
        left.source
            .cmp(&right.source)
            .then_with(|| left.payload_name.cmp(&right.payload_name))
            .then_with(|| left.target_name.cmp(&right.target_name))
            .then_with(|| left.contract_id.cmp(&right.contract_id))
    });
    contracts.dedup_by(|left, right| left.contract_id == right.contract_id);
    contracts
}

pub fn pcode_inject_contracts_from_program_compiler_specs(
    artifact_id: &str,
    compiler_specs: &[ProgramCompilerSpec],
) -> Vec<PcodeInjectContract> {
    let artifact_id = artifact_id.trim();
    let artifact_id = if artifact_id.is_empty() {
        "artifact:unknown"
    } else {
        artifact_id
    };
    let mut contracts = Vec::new();
    for compiler_spec in compiler_specs {
        let source = if compiler_spec.spec_file.trim().is_empty() {
            compiler_spec.compiler_id.trim()
        } else {
            compiler_spec.spec_file.trim()
        };
        let source = if source.is_empty() { "unknown" } else { source };
        for (payload_index, callfixup) in compiler_spec.callfixups.iter().enumerate() {
            let targets = if callfixup.targets.is_empty() {
                vec![None]
            } else {
                callfixup
                    .targets
                    .iter()
                    .map(|target| Some(target.trim().to_string()))
                    .collect::<Vec<_>>()
            };
            for target_name in targets {
                let target_name = target_name.filter(|target| !target.is_empty());
                let body_hash = callfixup
                    .pcode_body_hash
                    .as_deref()
                    .map(str::trim)
                    .filter(|hash| !hash.is_empty())
                    .map(ToOwned::to_owned)
                    .unwrap_or_else(|| {
                        stable_hash(json!([
                            PCODE_INJECT_CONTRACT_VERSION,
                            artifact_id,
                            &compiler_spec.compiler_spec_id,
                            &callfixup.name,
                            &target_name,
                            &callfixup.pcode_body
                        ]))
                    });
                let pcode_body = callfixup.pcode_body.as_deref();
                let pcode_opcodes = summarize_pcode_inject_body_opcodes(pcode_body);
                let falls_through = pcode_inject_body_falls_through(pcode_body);
                let input_parameters = callfixup
                    .input_parameters
                    .iter()
                    .enumerate()
                    .map(|(index, parameter)| {
                        compiler_inject_parameter_to_contract_parameter(
                            parameter,
                            index,
                            PcodeInjectParameterDirection::Input,
                        )
                    })
                    .collect::<Vec<_>>();
                let output_index_base = input_parameters.len();
                let output_parameters = callfixup
                    .output_parameters
                    .iter()
                    .enumerate()
                    .map(|(index, parameter)| {
                        compiler_inject_parameter_to_contract_parameter(
                            parameter,
                            output_index_base + index,
                            PcodeInjectParameterDirection::Output,
                        )
                    })
                    .collect::<Vec<_>>();
                let contract_id = format!(
                    "ghidra:callfixup:{}",
                    stable_hash(json!([
                        artifact_id,
                        &compiler_spec.compiler_spec_id,
                        &callfixup.name,
                        &target_name,
                        &body_hash
                    ]))
                );
                let evidence = normalize_id_list(&[
                    contract_id.clone(),
                    compiler_spec.compiler_spec_id.clone(),
                    format!("ghidra:compiler_spec:{}", compiler_spec.spec_file),
                ]);
                contracts.push(PcodeInjectContract {
                    contract_id,
                    function_id: None,
                    artifact_id: artifact_id.to_string(),
                    address: 0,
                    kind: PcodeInjectKind::CallFixup,
                    payload_name: callfixup.name.trim().to_string(),
                    payload_id: Some(payload_index as i32),
                    source: source.to_string(),
                    target_name,
                    target_address: None,
                    userop_name: None,
                    userop_index: None,
                    param_shift: callfixup.param_shift,
                    dynamic: callfixup.dynamic,
                    incidental_copy: callfixup.incidental_copy,
                    input_parameters,
                    output_parameters,
                    pcode_opcodes,
                    body_hash,
                    replaces_call: true,
                    falls_through,
                    confidence: if callfixup.pcode_body.is_some() {
                        0.88
                    } else {
                        0.72
                    },
                    evidence,
                    authority: "derived_fact".to_string(),
                });
            }
        }
        for (payload_index, callotherfixup) in compiler_spec.callotherfixups.iter().enumerate() {
            let body_hash = callotherfixup
                .pcode_body_hash
                .as_deref()
                .map(str::trim)
                .filter(|hash| !hash.is_empty())
                .map(ToOwned::to_owned)
                .unwrap_or_else(|| {
                    stable_hash(json!([
                        PCODE_INJECT_CONTRACT_VERSION,
                        artifact_id,
                        &compiler_spec.compiler_spec_id,
                        &callotherfixup.targetop,
                        &callotherfixup.pcode_body
                    ]))
                });
            let pcode_body = callotherfixup.pcode_body.as_deref();
            let pcode_opcodes = summarize_pcode_inject_body_opcodes(pcode_body);
            let falls_through = pcode_inject_body_falls_through(pcode_body);
            let (input_parameters, output_parameters) = compiler_inject_parameters_to_contract(
                &callotherfixup.input_parameters,
                &callotherfixup.output_parameters,
            );
            let contract_id = format!(
                "ghidra:callotherfixup:{}",
                stable_hash(json!([
                    artifact_id,
                    &compiler_spec.compiler_spec_id,
                    &callotherfixup.targetop,
                    &body_hash
                ]))
            );
            let evidence = normalize_id_list(&[
                contract_id.clone(),
                compiler_spec.compiler_spec_id.clone(),
                format!("ghidra:compiler_spec:{}", compiler_spec.spec_file),
            ]);
            contracts.push(PcodeInjectContract {
                contract_id,
                function_id: None,
                artifact_id: artifact_id.to_string(),
                address: 0,
                kind: PcodeInjectKind::CallOtherFixup,
                payload_name: callotherfixup.targetop.trim().to_string(),
                payload_id: Some(payload_index as i32),
                source: source.to_string(),
                target_name: None,
                target_address: None,
                userop_name: normalize_optional_id(Some(&callotherfixup.targetop)),
                userop_index: Some(payload_index as u32),
                param_shift: callotherfixup.param_shift,
                dynamic: callotherfixup.dynamic,
                incidental_copy: callotherfixup.incidental_copy,
                input_parameters,
                output_parameters,
                pcode_opcodes,
                body_hash,
                replaces_call: false,
                falls_through,
                confidence: if callotherfixup.pcode_body.is_some() {
                    0.86
                } else {
                    0.7
                },
                evidence,
                authority: "derived_fact".to_string(),
            });
        }
    }
    contracts.sort_by(|left, right| {
        left.source
            .cmp(&right.source)
            .then_with(|| left.payload_name.cmp(&right.payload_name))
            .then_with(|| left.target_name.cmp(&right.target_name))
            .then_with(|| left.contract_id.cmp(&right.contract_id))
    });
    contracts.dedup_by(|left, right| left.contract_id == right.contract_id);
    contracts
}

pub fn bind_pcode_inject_contracts_to_program_targets(
    load: &BinaryLoadReport,
    program: &ThirProgram,
    contracts: &[PcodeInjectContract],
) -> Vec<PcodeInjectContract> {
    let mut bound = contracts
        .iter()
        .map(|contract| bind_pcode_inject_contract_to_program_targets(load, program, contract))
        .collect::<Vec<_>>();
    bound.sort_by(|left, right| {
        left.function_id
            .cmp(&right.function_id)
            .then_with(|| left.target_address.cmp(&right.target_address))
            .then_with(|| left.kind.cmp(&right.kind))
            .then_with(|| left.payload_name.cmp(&right.payload_name))
            .then_with(|| left.contract_id.cmp(&right.contract_id))
    });
    bound.dedup_by(|left, right| left.contract_id == right.contract_id);
    bound
}

pub fn bind_callother_pcode_inject_contracts_to_userop_sites(
    program: &ThirProgram,
    contracts: &[PcodeInjectContract],
) -> Vec<PcodeInjectContract> {
    let sites = callother_userop_sites(program);
    let mut bound = Vec::new();
    for contract in contracts {
        bound.push(contract.clone());
        if !callother_contract_needs_userop_site_binding(contract) {
            continue;
        }
        for site in sites
            .iter()
            .filter(|site| callother_userop_site_matches_contract(site, contract))
        {
            bound.push(callother_site_bound_pcode_inject_contract(contract, site));
        }
    }
    bound.sort_by(|left, right| {
        left.function_id
            .cmp(&right.function_id)
            .then_with(|| left.address.cmp(&right.address))
            .then_with(|| left.kind.cmp(&right.kind))
            .then_with(|| left.payload_name.cmp(&right.payload_name))
            .then_with(|| left.contract_id.cmp(&right.contract_id))
    });
    bound.dedup_by(|left, right| left.contract_id == right.contract_id);
    bound
}

