pub fn pcode_execution_contracts_from_ghidra_oracle_symbolic_summaries(
    artifact_id: &str,
    fixture: Option<&GhidraOracleFixture>,
    summaries: &[GhidraOracleSymbolicSummaryFact],
) -> Vec<PcodeExecutionContract> {
    summaries
        .iter()
        .filter_map(|summary| {
            let entry_address = parse_ghidra_u64_address(&summary.entry_point)?;
            let fixture_evidence = fixture
                .map(|fixture| fixture.evidence_ids.clone())
                .unwrap_or_default();
            let evidence = normalize_id_list(
                &std::iter::once(summary.summary_id.clone())
                    .chain(summary.evidence_ids.iter().cloned())
                    .chain(fixture_evidence)
                    .collect::<Vec<_>>(),
            );
            let symbolic_preconditions = summary
                .preconditions
                .iter()
                .map(ghidra_oracle_precondition_to_pcode)
                .collect::<Vec<_>>();
            let symbolic_values = summary
                .symbolic_values
                .iter()
                .map(ghidra_oracle_symbolic_value_to_pcode)
                .collect::<Vec<_>>();
            let symbolic_state = Some(PcodeSymbolicStateSummary {
                summary_id: summary.summary_id.clone(),
                registers_read: summary.registers_read.clone(),
                registers_updated: summary.registers_updated.clone(),
                memory_witnesses: summary
                    .memory_witnesses
                    .iter()
                    .map(ghidra_oracle_memory_witness_to_pcode)
                    .collect(),
                valuation_hash: summary.valuation_hash.clone(),
                evidence: evidence.clone(),
            });
            let step_count = symbolic_preconditions
                .iter()
                .map(|precondition| precondition.step_index)
                .max()
                .map(|step| step + 1)
                .unwrap_or(0);
            let lazy_load_count = summary
                .memory_witnesses
                .iter()
                .filter(|witness| {
                    parse_memory_witness_kind(&witness.kind) == PcodeMemoryWitnessKind::Load
                })
                .count() as u32;
            let write_count = summary
                .memory_witnesses
                .iter()
                .filter(|witness| {
                    parse_memory_witness_kind(&witness.kind) == PcodeMemoryWitnessKind::Store
                })
                .count() as u32;
            let language_id =
                fixture.and_then(|fixture| fixture.program_summary.language_id.clone());
            let compiler_spec_id =
                fixture.and_then(|fixture| fixture.program_summary.compiler_spec_id.clone());
            let contract_id = format!(
                "ghidra:pcode_execution:symbolic_summary:{}",
                stable_hash(json!([
                    artifact_id,
                    &summary.summary_id,
                    &summary.entry_point,
                    &summary.valuation_hash
                ]))
            );
            let execution_hash = stable_hash(json!([
                PCODE_EXECUTION_CONTRACT_VERSION,
                &summary.summary_id,
                &summary.preconditions,
                &summary.symbolic_values,
                &summary.memory_witnesses,
                &summary.model_bindings,
                &summary.solver_status
            ]));
            Some(PcodeExecutionContract {
                contract_id,
                function_id: summary.function_id.clone(),
                artifact_id: artifact_id.to_string(),
                entry_address,
                stop_address: None,
                thread_id: summary.thread_id.clone(),
                snapshot_id: None,
                domain: PcodeExecutionDomain::Symbolic,
                language_id,
                compiler_spec_id,
                userop_library: Some("ghidra-symbolic-summary-z3".to_string()),
                inject_ids: Vec::new(),
                initial_observations: Vec::new(),
                final_observations: Vec::new(),
                taint_flows: Vec::new(),
                symbolic_preconditions,
                symbolic_values,
                symbolic_state,
                solver_status: parse_solver_status(&summary.solver_status),
                solver_model_bindings: summary
                    .model_bindings
                    .iter()
                    .map(ghidra_oracle_model_binding_to_pcode)
                    .collect(),
                branch_decisions: summary
                    .preconditions
                    .iter()
                    .map(|precondition| {
                        format!(
                            "{}:{}:{}",
                            precondition
                                .address
                                .as_deref()
                                .unwrap_or(summary.entry_point.as_str()),
                            precondition.branch_taken,
                            precondition.precondition_id
                        )
                    })
                    .collect(),
                executed_opcodes: Vec::new(),
                step_count,
                max_steps: None,
                lazy_load_count,
                write_count,
                terminated: true,
                fault: None,
                execution_hash,
                confidence: 0.9,
                evidence,
                authority: "observed_fact".to_string(),
            })
        })
        .collect()
}

pub fn decompiler_diagnostic_contracts_from_ghidra_oracle_diagnostics(
    artifact_id: &str,
    fixture: Option<&GhidraOracleFixture>,
    diagnostics: &[GhidraOracleDecompilerDiagnosticFact],
) -> Vec<DecompilerDiagnosticContract> {
    diagnostics
        .iter()
        .map(|diagnostic| {
            let fixture_evidence = fixture
                .map(|fixture| fixture.evidence_ids.clone())
                .unwrap_or_default();
            let evidence = normalize_id_list(
                &std::iter::once(diagnostic.diagnostic_id.clone())
                    .chain(diagnostic.evidence_ids.iter().cloned())
                    .chain(fixture_evidence)
                    .collect::<Vec<_>>(),
            );
            let address = diagnostic
                .address
                .as_deref()
                .and_then(parse_ghidra_u64_address)
                .or_else(|| parse_ghidra_u64_address(&diagnostic.entry_point));
            let category = parse_decompiler_diagnostic_category(&diagnostic.category);
            let severity = parse_decompiler_diagnostic_severity(&diagnostic.severity);
            let placement = parse_decompiler_diagnostic_placement(&diagnostic.placement);
            let contract_id = format!(
                "ghidra:decompiler_diagnostic_contract:{}",
                stable_hash(json!([
                    artifact_id,
                    &diagnostic.diagnostic_id,
                    &diagnostic.function_id,
                    &diagnostic.entry_point,
                    &diagnostic.address,
                    &diagnostic.category,
                    &diagnostic.severity,
                    &diagnostic.message
                ]))
            );
            DecompilerDiagnosticContract {
                contract_id,
                function_id: diagnostic.function_id.clone(),
                artifact_id: artifact_id.to_string(),
                address,
                category,
                severity: severity.clone(),
                placement,
                message: diagnostic.message.clone(),
                source_pass: diagnostic.source_pass.clone(),
                source_rule: diagnostic.source_rule.clone(),
                affects_control_flow: diagnostic.affects_control_flow,
                affects_prototype: diagnostic.affects_prototype,
                affects_data_flow: diagnostic.affects_data_flow,
                remediation: diagnostic.remediation.clone(),
                confidence: diagnostic_confidence(&severity, diagnostic.completed),
                evidence,
                authority: "observed_fact".to_string(),
            }
        })
        .collect()
}

pub fn decompiler_diagnostic_contracts_from_ghidra_oracle_annotations(
    artifact_id: &str,
    fixture: Option<&GhidraOracleFixture>,
    annotations: &[GhidraOracleAnnotationFact],
) -> Vec<DecompilerDiagnosticContract> {
    let fixture_evidence = fixture
        .map(|fixture| fixture.evidence_ids.clone())
        .unwrap_or_default();
    annotations
        .iter()
        .map(|annotation| {
            let evidence = normalize_id_list(
                &std::iter::once(annotation.annotation_id.clone())
                    .chain(annotation.evidence_ids.iter().cloned())
                    .chain(fixture_evidence.iter().cloned())
                    .collect::<Vec<_>>(),
            );
            let severity = decompiler_diagnostic_severity_from_annotation(annotation);
            let category = decompiler_diagnostic_category_from_annotation(annotation);
            let placement = decompiler_diagnostic_placement_from_annotation(annotation);
            let address = parse_ghidra_u64_address(&annotation.address).or_else(|| {
                annotation
                    .entry_point
                    .as_deref()
                    .and_then(parse_ghidra_u64_address)
            });
            let contract_id = format!(
                "ghidra:annotation_diagnostic_contract:{}",
                stable_hash(json!([
                    artifact_id,
                    &annotation.annotation_id,
                    &annotation.kind,
                    &annotation.function_id,
                    &annotation.entry_point,
                    &annotation.address,
                    &annotation.comment_type,
                    annotation.bookmark_id,
                    &annotation.bookmark_type,
                    &annotation.bookmark_category,
                    &annotation.message
                ]))
            );
            DecompilerDiagnosticContract {
                contract_id,
                function_id: annotation.function_id.clone(),
                artifact_id: artifact_id.to_string(),
                address,
                category: category.clone(),
                severity: severity.clone(),
                placement,
                message: annotation.message.clone(),
                source_pass: annotation
                    .source_api
                    .clone()
                    .or_else(|| Some("Ghidra annotation".to_string())),
                source_rule: annotation
                    .comment_type
                    .clone()
                    .or_else(|| annotation.bookmark_type.clone()),
                affects_control_flow: matches!(
                    category,
                    DecompilerDiagnosticCategory::Flow | DecompilerDiagnosticCategory::JumpTable
                ),
                affects_prototype: matches!(
                    category,
                    DecompilerDiagnosticCategory::Prototype
                        | DecompilerDiagnosticCategory::ParameterId
                ),
                affects_data_flow: matches!(
                    category,
                    DecompilerDiagnosticCategory::StackPointer
                        | DecompilerDiagnosticCategory::TypeRecovery
                        | DecompilerDiagnosticCategory::VariableMerge
                        | DecompilerDiagnosticCategory::DataType
                ),
                remediation: Some(
                    "Preserve Ghidra annotation uncertainty in reconstruction validators."
                        .to_string(),
                ),
                confidence: diagnostic_confidence(&severity, true),
                evidence,
                authority: "observed_fact".to_string(),
            }
        })
        .collect()
}

fn decompiler_diagnostic_severity_from_annotation(
    annotation: &GhidraOracleAnnotationFact,
) -> DecompilerDiagnosticSeverity {
    if annotation.kind.eq_ignore_ascii_case("bookmark") {
        match annotation
            .bookmark_type
            .as_deref()
            .unwrap_or_default()
            .trim()
            .to_ascii_lowercase()
            .as_str()
        {
            "error" => DecompilerDiagnosticSeverity::Error,
            "warning" | "warn" => DecompilerDiagnosticSeverity::Warning,
            "info" | "note" | "analysis" => DecompilerDiagnosticSeverity::Info,
            _ => DecompilerDiagnosticSeverity::Unknown,
        }
    } else {
        DecompilerDiagnosticSeverity::Info
    }
}

fn decompiler_diagnostic_placement_from_annotation(
    annotation: &GhidraOracleAnnotationFact,
) -> DecompilerDiagnosticPlacement {
    if annotation.kind.eq_ignore_ascii_case("bookmark") {
        return DecompilerDiagnosticPlacement::Bookmark;
    }
    match annotation
        .comment_type
        .as_deref()
        .unwrap_or_default()
        .trim()
        .to_ascii_lowercase()
        .as_str()
    {
        "plate" | "pre" => DecompilerDiagnosticPlacement::Header,
        "eol" | "post" | "repeatable" => DecompilerDiagnosticPlacement::Body,
        _ => DecompilerDiagnosticPlacement::Unknown,
    }
}

fn decompiler_diagnostic_category_from_annotation(
    annotation: &GhidraOracleAnnotationFact,
) -> DecompilerDiagnosticCategory {
    let tokens = [
        annotation.bookmark_category.as_deref().unwrap_or_default(),
        annotation.bookmark_type.as_deref().unwrap_or_default(),
        annotation.comment_type.as_deref().unwrap_or_default(),
        &annotation.message,
    ]
    .join(" ")
    .to_ascii_lowercase()
    .replace(['-', '_'], " ");
    if tokens.contains("jump table") || tokens.contains("jumptable") || tokens.contains("switch") {
        DecompilerDiagnosticCategory::JumpTable
    } else if tokens.contains("stack pointer") || tokens.contains("stack") {
        DecompilerDiagnosticCategory::StackPointer
    } else if tokens.contains("prototype") || tokens.contains("signature") {
        DecompilerDiagnosticCategory::Prototype
    } else if tokens.contains("paramid") || tokens.contains("parameter") {
        DecompilerDiagnosticCategory::ParameterId
    } else if tokens.contains("type recovery") {
        DecompilerDiagnosticCategory::TypeRecovery
    } else if tokens.contains("variable merge") || tokens.contains("merge") {
        DecompilerDiagnosticCategory::VariableMerge
    } else if tokens.contains("data type")
        || tokens.contains("datatype")
        || tokens.contains("structure")
        || tokens.contains("layout")
    {
        DecompilerDiagnosticCategory::DataType
    } else if tokens.contains("flow") || tokens.contains("control") {
        DecompilerDiagnosticCategory::Flow
    } else {
        DecompilerDiagnosticCategory::Unknown
    }
}

pub fn function_semantic_signatures_from_ghidra_oracle_semantic_signatures(
    artifact_id: &str,
    fixture: Option<&GhidraOracleFixture>,
    signatures: &[GhidraOracleSemanticSignatureFact],
) -> Vec<FunctionSemanticSignature> {
    let fixture_evidence = fixture
        .map(|fixture| fixture.evidence_ids.clone())
        .unwrap_or_default();
    let mut lowered = signatures
        .iter()
        .filter_map(|signature| {
            let entry_address = parse_ghidra_u64_address(&signature.entry_point)?;
            let function_id = signature
                .function_id
                .clone()
                .unwrap_or_else(|| format!("ghidra:function:{entry_address:x}"));
            let mut feature_hashes = signature
                .feature_hashes
                .iter()
                .map(|hash| format!("ghidra-bsim:{}", hash.trim().to_ascii_lowercase()))
                .collect::<Vec<_>>();
            for debug_feature in &signature.debug_features {
                feature_hashes.push(format!(
                    "ghidra-bsim-debug:{}:{}",
                    debug_feature.kind.trim().to_ascii_lowercase(),
                    debug_feature.hash.trim().to_ascii_lowercase()
                ));
            }
            feature_hashes.sort();

            let call_targets = signature
                .call_targets
                .iter()
                .filter_map(|target| parse_ghidra_u64_address(target))
                .collect::<BTreeSet<_>>()
                .into_iter()
                .collect::<Vec<_>>();
            let mut quality_flags = BTreeSet::new();
            if feature_hashes.is_empty() {
                quality_flags.insert(SignatureQualityFlag::EmptyFunction);
            }
            if signature.has_unimplemented {
                quality_flags.insert(SignatureQualityFlag::HasUnimplementedInstructions);
            }
            if signature.has_bad_data {
                quality_flags.insert(SignatureQualityFlag::HasBadDataFlow);
            }
            let evidence = normalize_id_list(
                &std::iter::once(signature.signature_id.clone())
                    .chain(signature.evidence_ids.iter().cloned())
                    .chain(fixture_evidence.iter().cloned())
                    .collect::<Vec<_>>(),
            );
            let unique_feature_count = feature_hashes.iter().collect::<BTreeSet<_>>().len();
            let self_significance =
                (feature_hashes.len() as f64).sqrt() + (unique_feature_count as f64 * 0.25);
            let lowered_signature_id = format!(
                "recon:function_signature:ghidra_oracle:{}",
                stable_hash(json!([
                    artifact_id,
                    &signature.signature_id,
                    &function_id,
                    &signature.feature_version,
                    signature.signature_settings,
                    signature.decompiler_major_version,
                    signature.decompiler_minor_version,
                    &feature_hashes,
                    &call_targets
                ]))
            );

            Some(FunctionSemanticSignature {
                signature_id: lowered_signature_id,
                function_id,
                artifact_id: artifact_id.to_string(),
                feature_version: format!(
                    "{}:settings:{}:decompiler:{}.{}",
                    signature.feature_version,
                    signature.signature_settings,
                    signature.decompiler_major_version.unwrap_or_default(),
                    signature.decompiler_minor_version.unwrap_or_default()
                ),
                feature_hashes,
                call_targets,
                reference_feature_ids: Vec::new(),
                prototype_contract_ids: Vec::new(),
                quality_flags: quality_flags.into_iter().collect(),
                block_count: 0,
                statement_count: signature.feature_hashes.len(),
                branch_count: 0,
                call_count: signature.call_targets.len(),
                reference_count: 0,
                reference_call_count: 0,
                prototype_parameter_count: 0,
                prototype_has_varargs: false,
                prototype_has_no_return: false,
                return_count: 0,
                self_significance,
                evidence,
                authority: "observed_fact".to_string(),
            })
        })
        .collect::<Vec<_>>();
    lowered.sort_by(|left, right| left.signature_id.cmp(&right.signature_id));
    lowered
}

pub fn function_identifier_signatures_from_ghidra_oracle_function_id_facts(
    artifact_id: &str,
    fixture: Option<&GhidraOracleFixture>,
    facts: &[GhidraOracleFunctionIdFact],
) -> Vec<FunctionIdentifierSignature> {
    let fixture_evidence = fixture
        .map(|fixture| fixture.evidence_ids.clone())
        .unwrap_or_default();
    let mut signatures = facts
        .iter()
        .filter_map(|fact| {
            let entry_address = parse_ghidra_u64_address(&fact.entry_point)?;
            let function_id = fact
                .function_id
                .clone()
                .unwrap_or_else(|| format!("ghidra:function:{entry_address:x}"));
            let match_tokens = fact
                .matches
                .iter()
                .flat_map(|fid_match| {
                    [
                        format!(
                            "ghidra-fid:match:function:{}",
                            normalize_feature_token(&fid_match.function_name)
                        ),
                        format!(
                            "ghidra-fid:match:library:{}",
                            normalize_feature_token(
                                fid_match
                                    .library_family_name
                                    .as_deref()
                                    .unwrap_or("unknown")
                            )
                        ),
                        format!(
                            "ghidra-fid:match:mode:{}",
                            normalize_feature_token(
                                fid_match
                                    .primary_function_match_mode
                                    .as_deref()
                                    .unwrap_or("unknown")
                            )
                        ),
                    ]
                })
                .collect::<Vec<_>>();
            let mut full_tokens = vec![
                format!("ghidra-fid:full_hash:{}", fact.full_hash),
                format!(
                    "ghidra-fid:code_units:{}",
                    count_bucket(fact.code_unit_size as usize)
                ),
                format!(
                    "ghidra-fid:algorithm:{}",
                    normalize_feature_token(&fact.hash_algorithm)
                ),
            ];
            full_tokens.extend(match_tokens.clone());
            full_tokens.sort();
            full_tokens.dedup();
            let mut specific_tokens = vec![
                format!("ghidra-fid:specific_hash:{}", fact.specific_hash),
                format!(
                    "ghidra-fid:specific_additional:{}",
                    count_bucket(fact.specific_hash_additional_size as usize)
                ),
            ];
            specific_tokens.extend(match_tokens);
            specific_tokens.sort();
            specific_tokens.dedup();
            let evidence = normalize_id_list(
                &std::iter::once(fact.fid_id.clone())
                    .chain(fact.evidence_ids.iter().cloned())
                    .chain(fact.matches.iter().flat_map(|fid_match| {
                        std::iter::once(fid_match.match_id.clone())
                            .chain(fid_match.evidence_ids.iter().cloned())
                    }))
                    .chain(fixture_evidence.iter().cloned())
                    .collect::<Vec<_>>(),
            );
            let signature_id = format!(
                "recon:function_identifier_signature:ghidra_oracle:{}",
                stable_hash(json!([
                    artifact_id,
                    &fact.fid_id,
                    &function_id,
                    &fact.feature_version,
                    &fact.hash_algorithm,
                    fact.short_hash_code_unit_length,
                    fact.medium_hash_code_unit_length,
                    fact.code_unit_size,
                    &fact.full_hash,
                    fact.specific_hash_additional_size,
                    &fact.specific_hash,
                    &full_tokens,
                    &specific_tokens
                ]))
            );
            Some(FunctionIdentifierSignature {
                signature_id,
                function_id,
                artifact_id: artifact_id.to_string(),
                feature_version: format!(
                    "{}:short:{}:medium:{}:algorithm:{}",
                    fact.feature_version,
                    fact.short_hash_code_unit_length,
                    fact.medium_hash_code_unit_length,
                    fact.hash_algorithm
                ),
                code_unit_size: fact.code_unit_size,
                full_hash: fact.full_hash.clone(),
                specific_hash_additional_size: fact.specific_hash_additional_size,
                specific_hash: fact.specific_hash.clone(),
                full_tokens,
                specific_tokens,
                call_targets: Vec::new(),
                reference_feature_ids: Vec::new(),
                prototype_contract_ids: Vec::new(),
                call_count: 0,
                reference_count: 0,
                reference_call_count: 0,
                prototype_parameter_count: 0,
                statement_count: fact.code_unit_size as usize,
                evidence,
                authority: "observed_fact".to_string(),
            })
        })
        .collect::<Vec<_>>();
    signatures.sort_by(|left, right| left.signature_id.cmp(&right.signature_id));
    signatures
}

fn ghidra_oracle_precondition_to_pcode(
    precondition: &GhidraOracleSymbolicPreconditionFact,
) -> PcodeSymbolicPrecondition {
    PcodeSymbolicPrecondition {
        precondition_id: precondition.precondition_id.clone(),
        step_index: precondition.step_index,
        address: precondition
            .address
            .as_deref()
            .and_then(parse_ghidra_u64_address),
        pcode_op_id: precondition.pcode_op_id.clone(),
        branch_taken: precondition.branch_taken,
        serialized_expr: precondition.serialized_expr.clone(),
        display_expr: precondition.display_expr.clone(),
        solver_status: parse_solver_status(&precondition.solver_status),
        model_bindings: precondition
            .model_bindings
            .iter()
            .map(ghidra_oracle_model_binding_to_pcode)
            .collect(),
        evidence: normalize_id_list(
            &std::iter::once(precondition.precondition_id.clone())
                .chain(precondition.evidence_ids.iter().cloned())
                .collect::<Vec<_>>(),
        ),
    }
}

fn ghidra_oracle_symbolic_value_to_pcode(
    value: &GhidraOracleSymbolicValueFact,
) -> PcodeSymbolicValue {
    PcodeSymbolicValue {
        value_id: value.value_id.clone(),
        kind: parse_symbolic_value_kind(&value.kind),
        name: value.name.clone(),
        space: value.space.clone(),
        offset: value.offset.as_deref().and_then(parse_ghidra_i64_offset),
        byte_len: value.byte_len,
        serialized_expr: value.serialized_expr.clone(),
        display_expr: value.display_expr.clone(),
        concrete_value: value.concrete_value.clone(),
        evidence: normalize_id_list(
            &std::iter::once(value.value_id.clone())
                .chain(value.evidence_ids.iter().cloned())
                .collect::<Vec<_>>(),
        ),
    }
}

fn ghidra_oracle_memory_witness_to_pcode(
    witness: &GhidraOracleMemoryWitnessFact,
) -> PcodeMemoryWitness {
    PcodeMemoryWitness {
        witness_id: witness.witness_id.clone(),
        kind: parse_memory_witness_kind(&witness.kind),
        address_expr: witness.address_expr.clone(),
        address_display: witness.address_display.clone(),
        byte_len: witness.byte_len,
        value_expr: witness.value_expr.clone(),
        value_display: witness.value_display.clone(),
        evidence: normalize_id_list(
            &std::iter::once(witness.witness_id.clone())
                .chain(witness.evidence_ids.iter().cloned())
                .collect::<Vec<_>>(),
        ),
    }
}

fn ghidra_oracle_model_binding_to_pcode(
    binding: &GhidraOracleSymbolicModelBinding,
) -> PcodeSymbolicModelBinding {
    PcodeSymbolicModelBinding {
        name: binding.name.clone(),
        value: binding.value.clone(),
        value_hash: binding.value_hash.clone(),
    }
}

fn parse_solver_status(status: &str) -> PcodeSolverStatus {
    match status.trim().to_ascii_lowercase().as_str() {
        "sat" | "satisfiable" => PcodeSolverStatus::Satisfiable,
        "unsat" | "unsatisfiable" => PcodeSolverStatus::Unsatisfiable,
        "not_checked" | "not-checked" | "not checked" => PcodeSolverStatus::NotChecked,
        _ => PcodeSolverStatus::Unknown,
    }
}

fn parse_symbolic_value_kind(kind: &str) -> PcodeSymbolicValueKind {
    match kind.trim().to_ascii_lowercase().as_str() {
        "register" => PcodeSymbolicValueKind::Register,
        "memory" => PcodeSymbolicValueKind::Memory,
        "unique" => PcodeSymbolicValueKind::Unique,
        "input" => PcodeSymbolicValueKind::Input,
        "output" => PcodeSymbolicValueKind::Output,
        "precondition" => PcodeSymbolicValueKind::Precondition,
        _ => PcodeSymbolicValueKind::Unknown,
    }
}

fn parse_memory_witness_kind(kind: &str) -> PcodeMemoryWitnessKind {
    match kind.trim().to_ascii_lowercase().as_str() {
        "load" => PcodeMemoryWitnessKind::Load,
        "store" => PcodeMemoryWitnessKind::Store,
        _ => PcodeMemoryWitnessKind::Unknown,
    }
}

fn parse_decompiler_diagnostic_category(kind: &str) -> DecompilerDiagnosticCategory {
    match kind.trim().to_ascii_lowercase().as_str() {
        "flow" => DecompilerDiagnosticCategory::Flow,
        "jump_table" | "jumptable" | "jump-table" => DecompilerDiagnosticCategory::JumpTable,
        "stack_pointer" | "stack-pointer" | "stackptr" => {
            DecompilerDiagnosticCategory::StackPointer
        }
        "prototype" => DecompilerDiagnosticCategory::Prototype,
        "parameter_id" | "paramid" | "parameter-id" => DecompilerDiagnosticCategory::ParameterId,
        "type_recovery" | "type-recovery" => DecompilerDiagnosticCategory::TypeRecovery,
        "variable_merge" | "variable-merge" => DecompilerDiagnosticCategory::VariableMerge,
        "data_type" | "datatype" | "data-type" => DecompilerDiagnosticCategory::DataType,
        "decompiler_action" | "action" | "rule" => DecompilerDiagnosticCategory::DecompilerAction,
        "export" => DecompilerDiagnosticCategory::Export,
        _ => DecompilerDiagnosticCategory::Unknown,
    }
}

fn parse_decompiler_diagnostic_severity(kind: &str) -> DecompilerDiagnosticSeverity {
    match kind.trim().to_ascii_lowercase().as_str() {
        "info" => DecompilerDiagnosticSeverity::Info,
        "warning" | "warn" => DecompilerDiagnosticSeverity::Warning,
        "error" => DecompilerDiagnosticSeverity::Error,
        "fatal" => DecompilerDiagnosticSeverity::Fatal,
        _ => DecompilerDiagnosticSeverity::Unknown,
    }
}

fn parse_decompiler_diagnostic_placement(kind: &str) -> DecompilerDiagnosticPlacement {
    match kind.trim().to_ascii_lowercase().as_str() {
        "header" => DecompilerDiagnosticPlacement::Header,
        "body" => DecompilerDiagnosticPlacement::Body,
        "bookmark" => DecompilerDiagnosticPlacement::Bookmark,
        "export" => DecompilerDiagnosticPlacement::Export,
        _ => DecompilerDiagnosticPlacement::Unknown,
    }
}

fn diagnostic_confidence(severity: &DecompilerDiagnosticSeverity, completed: bool) -> f64 {
    let base = match severity {
        DecompilerDiagnosticSeverity::Fatal => 0.96,
        DecompilerDiagnosticSeverity::Error => 0.92,
        DecompilerDiagnosticSeverity::Warning => 0.86,
        DecompilerDiagnosticSeverity::Info => 0.72,
        DecompilerDiagnosticSeverity::Unknown => 0.66,
    };
    if completed {
        base
    } else {
        (base + 0.03_f64).min(0.98_f64)
    }
}

fn parse_ghidra_u64_address(value: &str) -> Option<u64> {
    let value = value.trim();
    if value.is_empty() {
        return None;
    }
    let suffix = value.rsplit(':').next().unwrap_or(value).trim();
    parse_prefixed_u64(suffix)
}

fn parse_ghidra_i64_offset(value: &str) -> Option<i64> {
    parse_ghidra_u64_address(value).and_then(|value| i64::try_from(value).ok())
}

fn parse_prefixed_u64(value: &str) -> Option<u64> {
    let value = value.trim();
    if let Some(hex) = value
        .strip_prefix("0x")
        .or_else(|| value.strip_prefix("0X"))
    {
        u64::from_str_radix(hex, 16).ok()
    } else {
        value.parse::<u64>().ok()
    }
}

