fn compile_reconstruction_analysis_with_all_contracts(
    load: &BinaryLoadReport,
    program: &ThirProgram,
    reference_features: &[ReferenceSemanticFeature],
    prototype_contracts: &[FunctionPrototypeContract],
    data_type_contracts: &[DataTypeContract],
    structure_field_access_contracts: &[StructureFieldAccessContract],
    high_variable_contracts: &[HighVariableContract],
    parameter_measure_contracts: &[ParameterMeasureContract],
    pcode_inject_contracts: &[PcodeInjectContract],
    flow_override_contracts: &[FlowOverrideContract],
    variable_merge_contracts: &[VariableMergeContract],
    decompiler_rule_contracts: &[DecompilerRuleApplicationContract],
    jump_table_contracts: &[JumpTableContract],
    equate_contracts: &[EquateContract],
    external_linkage_contracts: &[ExternalLinkageContract],
) -> ReconstructionAnalysis {
    let reference_features = normalize_reference_semantic_features(reference_features);
    let prototype_contracts = normalize_function_prototype_contracts(program, prototype_contracts);
    let data_type_contracts = normalize_data_type_contracts(load, data_type_contracts);
    let structure_field_access_contracts =
        normalize_structure_field_access_contracts(load, program, structure_field_access_contracts);
    let high_variable_contracts =
        normalize_high_variable_contracts(load, program, high_variable_contracts);
    let parameter_measure_contracts =
        normalize_parameter_measure_contracts(load, program, parameter_measure_contracts);
    let pcode_inject_contracts =
        normalize_pcode_inject_contracts(load, program, pcode_inject_contracts);
    let derived_reference_override_contracts =
        flow_override_contracts_from_normalized_reference_override_features(
            load,
            program,
            &reference_features,
        );
    let derived_localized_prototype_override_contracts =
        flow_override_contracts_from_normalized_localized_prototype_overrides(
            load,
            program,
            &reference_features,
            &prototype_contracts,
        );
    let derived_pcode_inject_flow_override_contracts =
        flow_override_contracts_from_normalized_non_fallthrough_pcode_injects(
            load,
            program,
            &reference_features,
            &pcode_inject_contracts,
        );
    let derived_flow_override_contracts = derived_reference_override_contracts
        .into_iter()
        .chain(derived_localized_prototype_override_contracts)
        .chain(derived_pcode_inject_flow_override_contracts)
        .collect::<Vec<_>>();
    let flow_override_contracts = merge_explicit_and_derived_flow_override_contracts(
        flow_override_contracts,
        &derived_flow_override_contracts,
    );
    let flow_override_contracts =
        normalize_flow_override_contracts(load, program, &flow_override_contracts);
    let variable_merge_contracts =
        normalize_variable_merge_contracts(load, program, variable_merge_contracts);
    let decompiler_rule_contracts =
        normalize_decompiler_rule_contracts(load, program, decompiler_rule_contracts);
    let jump_table_contracts = normalize_jump_table_contracts(load, program, jump_table_contracts);
    let equate_contracts = normalize_equate_contracts(load, program, equate_contracts);
    let external_linkage_contracts =
        normalize_external_linkage_contracts(load, program, external_linkage_contracts);
    let data_type_dependency_plan =
        compile_data_type_dependency_plan(&load.artifact.artifact_id, &data_type_contracts);
    let signatures = compile_function_semantic_signatures_with_recovery_evidence(
        program,
        &reference_features,
        &prototype_contracts,
    );
    let identifier_signatures = compile_function_identifier_signatures_with_recovery_evidence(
        program,
        &reference_features,
        &prototype_contracts,
    );
    let hash_families = compile_function_hash_families(program, &identifier_signatures);
    let roles = derive_semantic_roles(load, program);
    let components = recover_components_with_all_contracts(
        load,
        program,
        &roles,
        &reference_features,
        &prototype_contracts,
        &structure_field_access_contracts,
        &high_variable_contracts,
        &parameter_measure_contracts,
        &pcode_inject_contracts,
        &flow_override_contracts,
        &variable_merge_contracts,
        &decompiler_rule_contracts,
        &jump_table_contracts,
        &equate_contracts,
        &external_linkage_contracts,
    );
    let plan = compile_reconstruction_plan_with_all_contracts(
        load,
        &components,
        &roles,
        &signatures,
        &prototype_contracts,
        &data_type_contracts,
        &data_type_dependency_plan,
        &structure_field_access_contracts,
        &high_variable_contracts,
        &parameter_measure_contracts,
        &pcode_inject_contracts,
        &flow_override_contracts,
        &variable_merge_contracts,
        &decompiler_rule_contracts,
        &jump_table_contracts,
        &equate_contracts,
        &external_linkage_contracts,
        program,
    );
    ReconstructionAnalysis {
        prototype_contracts,
        data_type_contracts,
        data_type_dependency_plan,
        structure_field_access_contracts,
        stack_frame_contracts: Vec::new(),
        call_stack_effect_contracts: Vec::new(),
        decompiler_diagnostic_contracts: Vec::new(),
        high_variable_contracts,
        parameter_measure_contracts,
        pcode_inject_contracts,
        pcode_execution_contracts: Vec::new(),
        flow_override_contracts,
        variable_merge_contracts,
        decompiler_rule_contracts,
        jump_table_contracts,
        equate_contracts,
        external_linkage_contracts,
        signatures,
        identifier_signatures,
        hash_families,
        roles,
        components,
        plan,
    }
}

pub fn compile_function_semantic_signatures(
    program: &ThirProgram,
) -> Vec<FunctionSemanticSignature> {
    compile_function_semantic_signatures_with_reference_features(program, &[])
}

pub fn compile_function_semantic_signatures_with_reference_features(
    program: &ThirProgram,
    reference_features: &[ReferenceSemanticFeature],
) -> Vec<FunctionSemanticSignature> {
    compile_function_semantic_signatures_with_recovery_evidence(program, reference_features, &[])
}

pub fn compile_function_semantic_signatures_with_recovery_evidence(
    program: &ThirProgram,
    reference_features: &[ReferenceSemanticFeature],
    prototype_contracts: &[FunctionPrototypeContract],
) -> Vec<FunctionSemanticSignature> {
    let reference_features = normalize_reference_semantic_features(reference_features);
    let prototype_contracts = normalize_function_prototype_contracts(program, prototype_contracts);
    let references_by_function =
        reference_features_by_source_function(program, &reference_features);
    let contracts_by_function = prototype_contracts_by_function(program, &prototype_contracts);
    let mut signatures = program
        .functions
        .iter()
        .map(|function| {
            let references = references_by_function
                .get(&function.function_id)
                .map(Vec::as_slice)
                .unwrap_or(&[]);
            let contracts = contracts_by_function
                .get(&function.function_id)
                .map(Vec::as_slice)
                .unwrap_or(&[]);
            function_semantic_signature_with_recovery_evidence(function, references, contracts)
        })
        .collect::<Vec<_>>();
    signatures.sort_by(|left, right| left.signature_id.cmp(&right.signature_id));
    signatures
}

