pub fn compile_function_hash_families(
    program: &ThirProgram,
    signatures: &[FunctionIdentifierSignature],
) -> Vec<FunctionHashFamily> {
    let signature_by_function = signatures
        .iter()
        .map(|signature| (signature.function_id.as_str(), signature))
        .collect::<BTreeMap<_, _>>();
    let mut parents_by_function = BTreeMap::<String, BTreeSet<String>>::new();
    let mut children_by_function = BTreeMap::<String, BTreeSet<String>>::new();
    for signature in signatures {
        for target in &signature.call_targets {
            if let Some(child_function) = function_by_address(program, *target) {
                if child_function.function_id == signature.function_id {
                    continue;
                }
                children_by_function
                    .entry(signature.function_id.clone())
                    .or_default()
                    .insert(child_function.function_id.clone());
                parents_by_function
                    .entry(child_function.function_id.clone())
                    .or_default()
                    .insert(signature.function_id.clone());
            }
        }
    }

    let mut families = signatures
        .iter()
        .map(|signature| {
            let parent_signatures = parents_by_function
                .get(&signature.function_id)
                .into_iter()
                .flat_map(|parents| parents.iter())
                .filter_map(|function_id| signature_by_function.get(function_id.as_str()).copied())
                .collect::<Vec<_>>();
            let child_signatures = children_by_function
                .get(&signature.function_id)
                .into_iter()
                .flat_map(|children| children.iter())
                .filter_map(|function_id| signature_by_function.get(function_id.as_str()).copied())
                .collect::<Vec<_>>();
            let parent_signature_ids = parent_signatures
                .iter()
                .map(|parent| parent.signature_id.clone())
                .collect::<Vec<_>>();
            let child_signature_ids = child_signatures
                .iter()
                .map(|child| child.signature_id.clone())
                .collect::<Vec<_>>();
            let parent_full_hashes = parent_signatures
                .iter()
                .map(|parent| parent.full_hash.clone())
                .collect::<BTreeSet<_>>()
                .into_iter()
                .collect::<Vec<_>>();
            let child_full_hashes = child_signatures
                .iter()
                .map(|child| child.full_hash.clone())
                .collect::<BTreeSet<_>>()
                .into_iter()
                .collect::<Vec<_>>();
            let evidence = signature
                .evidence
                .iter()
                .cloned()
                .chain(parent_signature_ids.iter().cloned())
                .chain(child_signature_ids.iter().cloned())
                .collect::<BTreeSet<_>>()
                .into_iter()
                .collect::<Vec<_>>();
            let family_id = format!(
                "recon:function_hash_family:{}",
                stable_hash(json!([
                    FUNCTION_HASH_FAMILY_VERSION,
                    &signature.signature_id,
                    &parent_full_hashes,
                    &child_full_hashes
                ]))
            );
            FunctionHashFamily {
                family_id,
                signature_id: signature.signature_id.clone(),
                function_id: signature.function_id.clone(),
                artifact_id: signature.artifact_id.clone(),
                parent_signature_ids,
                child_signature_ids,
                parent_full_hashes,
                child_full_hashes,
                evidence,
                authority: "derived_fact".to_string(),
            }
        })
        .collect::<Vec<_>>();
    families.sort_by(|left, right| left.family_id.cmp(&right.family_id));
    families
}

pub fn compile_data_type_dependency_plan(
    artifact_id: &str,
    contracts: &[DataTypeContract],
) -> DataTypeDependencyPlan {
    let contracts = normalize_data_type_contracts_for_artifact(artifact_id, contracts);
    let contract_by_type = contracts
        .iter()
        .map(|contract| (contract.type_id.as_str(), contract))
        .collect::<BTreeMap<_, _>>();
    let mut hard_dependency_edges = BTreeSet::<DataTypeDependencyEdge>::new();
    let mut soft_dependency_edges = BTreeSet::<DataTypeDependencyEdge>::new();
    let mut supports_by_type = BTreeMap::<String, BTreeSet<String>>::new();
    let mut dependents_by_type = BTreeMap::<String, BTreeSet<String>>::new();

    for contract in &contracts {
        supports_by_type
            .entry(contract.type_id.clone())
            .or_default();
        for dependency_id in contract_hard_dependency_type_ids(contract, &contract_by_type) {
            hard_dependency_edges.insert(DataTypeDependencyEdge {
                dependent_type_id: contract.type_id.clone(),
                dependency_type_id: dependency_id.clone(),
            });
            if contract_by_type.contains_key(dependency_id.as_str()) {
                supports_by_type
                    .entry(contract.type_id.clone())
                    .or_default()
                    .insert(dependency_id.clone());
                dependents_by_type
                    .entry(dependency_id)
                    .or_default()
                    .insert(contract.type_id.clone());
            }
        }
        for dependency_id in contract_soft_dependency_type_ids(contract, &contract_by_type) {
            soft_dependency_edges.insert(DataTypeDependencyEdge {
                dependent_type_id: contract.type_id.clone(),
                dependency_type_id: dependency_id,
            });
        }
    }

    let mut ready = supports_by_type
        .iter()
        .filter(|&(_type_id, dependencies)| dependencies.is_empty()).map(|(type_id, _dependencies)| type_id.clone())
        .collect::<BTreeSet<_>>();
    let mut ordered_type_ids = Vec::new();
    while let Some(type_id) = ready.pop_first() {
        ordered_type_ids.push(type_id.clone());
        for dependent_id in dependents_by_type
            .remove(&type_id)
            .unwrap_or_default()
            .into_iter()
        {
            if let Some(dependencies) = supports_by_type.get_mut(&dependent_id) {
                dependencies.remove(&type_id);
                if dependencies.is_empty() {
                    ready.insert(dependent_id);
                }
            }
        }
    }

    let ordered = ordered_type_ids.iter().cloned().collect::<BTreeSet<_>>();
    let cycle_type_ids = supports_by_type
        .into_iter()
        .filter_map(|(type_id, dependencies)| {
            (!ordered.contains(&type_id) && !dependencies.is_empty()).then_some(type_id)
        })
        .collect::<Vec<_>>();
    ordered_type_ids.extend(cycle_type_ids.iter().cloned());

    let composite_type_ids = contracts
        .iter()
        .filter(|contract| matches!(contract.kind, DataTypeKind::Structure | DataTypeKind::Union))
        .map(|contract| contract.type_id.clone())
        .collect::<Vec<_>>();
    let evidence = contracts
        .iter()
        .flat_map(data_type_contract_evidence_ids)
        .collect::<BTreeSet<_>>()
        .into_iter()
        .collect::<Vec<_>>();
    let confidence = if contracts.is_empty() {
        0.0
    } else {
        contracts
            .iter()
            .map(|contract| contract.confidence)
            .sum::<f64>()
            / contracts.len() as f64
    };
    let hard_dependency_edges = hard_dependency_edges.into_iter().collect::<Vec<_>>();
    let soft_dependency_edges = soft_dependency_edges.into_iter().collect::<Vec<_>>();
    DataTypeDependencyPlan {
        plan_id: format!(
            "recon:data_type_dependency_plan:{}",
            stable_hash(json!([
                DATA_TYPE_DEPENDENCY_PLAN_VERSION,
                artifact_id,
                &ordered_type_ids,
                &hard_dependency_edges,
                &soft_dependency_edges,
                &cycle_type_ids
            ]))
        ),
        artifact_id: artifact_id.to_string(),
        composite_type_ids,
        ordered_type_ids,
        hard_dependency_edges,
        soft_dependency_edges,
        cycle_type_ids,
        evidence,
        confidence,
        authority: "derived_fact".to_string(),
    }
}

pub fn compare_function_semantic_signatures(
    left: &FunctionSemanticSignature,
    right: &FunctionSemanticSignature,
) -> FunctionSignatureComparison {
    let left_counts = feature_counts(&left.feature_hashes);
    let right_counts = feature_counts(&right.feature_hashes);
    let dot_product = left_counts
        .iter()
        .filter_map(|(feature_hash, left_count)| {
            right_counts
                .get(feature_hash)
                .map(|right_count| (*left_count as f64) * (*right_count as f64))
        })
        .sum::<f64>();
    let left_norm = squared_count_norm(&left_counts);
    let right_norm = squared_count_norm(&right_counts);
    let similarity = if left_norm == 0.0 || right_norm == 0.0 {
        0.0
    } else {
        dot_product / (left_norm.sqrt() * right_norm.sqrt())
    };
    let shared_feature_count = left_counts
        .keys()
        .filter(|feature_hash| right_counts.contains_key(*feature_hash))
        .count();
    FunctionSignatureComparison {
        left_signature_id: left.signature_id.clone(),
        right_signature_id: right.signature_id.clone(),
        similarity,
        significance: similarity * (shared_feature_count as f64).ln_1p(),
        shared_feature_count,
        left_feature_count: left.feature_hashes.len(),
        right_feature_count: right.feature_hashes.len(),
    }
}

pub fn match_function_semantic_signatures(
    source: &[FunctionSemanticSignature],
    destination: &[FunctionSemanticSignature],
    minimum_similarity: f64,
) -> Vec<FunctionSemanticMatch> {
    let minimum_similarity = minimum_similarity.clamp(0.0, 1.0);
    let mut matches = Vec::new();
    for source_signature in source {
        for destination_signature in destination {
            let comparison =
                compare_function_semantic_signatures(source_signature, destination_signature);
            if comparison.similarity < minimum_similarity {
                continue;
            }
            matches.push(function_semantic_match(
                source_signature,
                destination_signature,
                &comparison,
            ));
        }
    }
    matches.sort_by(|left, right| {
        right
            .confidence
            .partial_cmp(&left.confidence)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| {
                right
                    .similarity
                    .partial_cmp(&left.similarity)
                    .unwrap_or(std::cmp::Ordering::Equal)
            })
            .then_with(|| left.match_id.cmp(&right.match_id))
    });
    matches
}

pub fn function_match_review_receipt(
    function_match: &FunctionSemanticMatch,
    match_set_id: Option<String>,
    items: &[FunctionMatchMarkupItem],
) -> FunctionMatchReviewReceipt {
    let items = items
        .iter()
        .filter(|item| item.match_id == function_match.match_id)
        .cloned()
        .collect::<Vec<_>>();
    let markup_status = MatchMarkupStatus::from_items(&items);
    let item_ids = items
        .iter()
        .map(|item| item.item_id.clone())
        .collect::<BTreeSet<_>>()
        .into_iter()
        .collect::<Vec<_>>();
    let mut evidence = function_match
        .evidence
        .iter()
        .cloned()
        .collect::<BTreeSet<_>>();
    evidence.insert(function_match.match_id.clone());
    for item in &items {
        evidence.insert(item.item_id.clone());
        evidence.extend(item.evidence.iter().cloned());
    }
    let receipt_id = format!(
        "recon:function_match_review:{}",
        stable_hash(json!({
            "version": FUNCTION_MATCH_REVIEW_VERSION,
            "match_id": &function_match.match_id,
            "match_set_id": &match_set_id,
            "association_status": &function_match.status,
            "markup_status": &markup_status,
            "item_ids": &item_ids,
        }))
    );
    FunctionMatchReviewReceipt {
        receipt_id,
        match_id: function_match.match_id.clone(),
        match_set_id,
        association_status: function_match.status.clone(),
        markup_status,
        item_ids,
        applied_count: items
            .iter()
            .filter(|item| {
                item.status == MatchMarkupItemStatus::Added
                    || item.status == MatchMarkupItemStatus::Replaced
            })
            .count(),
        rejected_count: items
            .iter()
            .filter(|item| item.status == MatchMarkupItemStatus::Rejected)
            .count(),
        dont_care_count: items
            .iter()
            .filter(|item| item.status == MatchMarkupItemStatus::DontCare)
            .count(),
        dont_know_count: items
            .iter()
            .filter(|item| item.status == MatchMarkupItemStatus::DontKnow)
            .count(),
        error_count: items
            .iter()
            .filter(|item| item.status == MatchMarkupItemStatus::FailedApply)
            .count(),
        unexamined_count: items
            .iter()
            .filter(|item| item.status == MatchMarkupItemStatus::Unapplied)
            .count(),
        same_count: items
            .iter()
            .filter(|item| item.status == MatchMarkupItemStatus::Same)
            .count(),
        conflict_count: items
            .iter()
            .filter(|item| item.status == MatchMarkupItemStatus::Conflict)
            .count(),
        evidence: evidence.into_iter().collect(),
        authority: "derived_fact".to_string(),
    }
}

pub fn apply_function_match_association_decision(
    matches: &[FunctionSemanticMatch],
    target_match_id: &str,
    decision: MatchAssociationDecision,
    target_has_applied_markup: bool,
) -> Result<FunctionMatchAssociationDecisionResult, String> {
    let target_index = matches
        .iter()
        .position(|function_match| function_match.match_id == target_match_id)
        .ok_or_else(|| format!("unknown function match: {target_match_id}"))?;
    let mut matches = matches.to_vec();
    let mut transitions = Vec::new();

    match decision {
        MatchAssociationDecision::Accept => {
            let status = matches[target_index].status.clone();
            if status == MatchAssociationStatus::Accepted {
                return Ok(FunctionMatchAssociationDecisionResult {
                    matches,
                    transitions,
                });
            }
            if status.is_blocked() {
                return Err(format!(
                    "cannot accept blocked function match {target_match_id}: {status:?}"
                ));
            }
            set_match_status(
                &mut matches,
                target_index,
                target_match_id,
                MatchAssociationDecision::Accept,
                MatchAssociationStatus::Accepted,
                MatchAssociationTransitionReason::TargetAccepted,
                &mut transitions,
            );
            let target = matches[target_index].clone();
            for index in 0..matches.len() {
                if index == target_index
                    || !function_matches_are_related(&target, &matches[index])
                    || matches[index].status != MatchAssociationStatus::Available
                {
                    continue;
                }
                set_match_status(
                    &mut matches,
                    index,
                    target_match_id,
                    MatchAssociationDecision::Accept,
                    MatchAssociationStatus::Blocked,
                    MatchAssociationTransitionReason::RelatedBlockedByAcceptedTarget,
                    &mut transitions,
                );
            }
        }
        MatchAssociationDecision::Reject => {
            let status = matches[target_index].status.clone();
            if status == MatchAssociationStatus::Rejected {
                return Ok(FunctionMatchAssociationDecisionResult {
                    matches,
                    transitions,
                });
            }
            if status == MatchAssociationStatus::Accepted {
                return Err(format!(
                    "cannot reject accepted function match {target_match_id}"
                ));
            }
            set_match_status(
                &mut matches,
                target_index,
                target_match_id,
                MatchAssociationDecision::Reject,
                MatchAssociationStatus::Rejected,
                MatchAssociationTransitionReason::TargetRejected,
                &mut transitions,
            );
        }
        MatchAssociationDecision::Clear => {
            let status = matches[target_index].status.clone();
            if status != MatchAssociationStatus::Accepted
                && status != MatchAssociationStatus::Rejected
            {
                return Err(format!(
                    "cannot clear function match {target_match_id} with status {status:?}"
                ));
            }
            if status == MatchAssociationStatus::Accepted && target_has_applied_markup {
                return Err(format!(
                    "cannot clear accepted function match {target_match_id} with applied markup"
                ));
            }
            if status == MatchAssociationStatus::Accepted {
                set_match_status(
                    &mut matches,
                    target_index,
                    target_match_id,
                    MatchAssociationDecision::Clear,
                    MatchAssociationStatus::Available,
                    MatchAssociationTransitionReason::AcceptedTargetCleared,
                    &mut transitions,
                );
                for index in 0..matches.len() {
                    if index == target_index
                        || matches[index].status != MatchAssociationStatus::Blocked
                    {
                        continue;
                    }
                    let should_remain_blocked =
                        has_accepted_related_match(&matches, index, Some(target_index));
                    if !should_remain_blocked {
                        set_match_status(
                            &mut matches,
                            index,
                            target_match_id,
                            MatchAssociationDecision::Clear,
                            MatchAssociationStatus::Available,
                            MatchAssociationTransitionReason::RelatedUnblockedAfterAcceptedClear,
                            &mut transitions,
                        );
                    }
                }
            } else {
                let new_status = if has_accepted_related_match(&matches, target_index, None) {
                    MatchAssociationStatus::Blocked
                } else {
                    MatchAssociationStatus::Available
                };
                let reason = if new_status == MatchAssociationStatus::Blocked {
                    MatchAssociationTransitionReason::RejectedTargetClearedToBlocked
                } else {
                    MatchAssociationTransitionReason::RejectedTargetClearedToAvailable
                };
                set_match_status(
                    &mut matches,
                    target_index,
                    target_match_id,
                    MatchAssociationDecision::Clear,
                    new_status,
                    reason,
                    &mut transitions,
                );
            }
        }
    }

    transitions.sort_by(|left, right| left.transition_id.cmp(&right.transition_id));
    Ok(FunctionMatchAssociationDecisionResult {
        matches,
        transitions,
    })
}

pub fn derive_semantic_roles(load: &BinaryLoadReport, program: &ThirProgram) -> Vec<SemanticRole> {
    let evidence_by_function = evidence_by_function_and_role(load, program);
    let mut roles = Vec::new();
    for function in &program.functions {
        if is_entry_function(load, function) {
            roles.push(role_for(
                function,
                SemanticRoleKind::Entrypoint,
                0.72,
                Vec::new(),
                "derived_fact",
            ));
        }
        if let Some(evidence_by_role) = evidence_by_function.get(&function.function_id) {
            for (role, evidence) in evidence_by_role {
                roles.push(role_for(
                    function,
                    role.clone(),
                    role_confidence(role, evidence.len()),
                    evidence.clone(),
                    "hypothesis",
                ));
            }
        }
    }
    roles.sort_by(|left, right| left.role_id.cmp(&right.role_id));
    roles.dedup_by(|left, right| left.role_id == right.role_id);
    roles
}

