fn stack_frame_contract_from_ghidra_oracle_fact(
    load: &BinaryLoadReport,
    fact: &GhidraOracleStackFrameFact,
) -> Option<StackFrameContract> {
    let address = parse_ghidra_oracle_address(&fact.entry_point)?;
    let variables = fact
        .variables
        .iter()
        .map(stack_frame_variable_from_ghidra_oracle_fact)
        .collect::<Vec<_>>();
    let evidence = fact
        .evidence_ids
        .iter()
        .cloned()
        .chain(std::iter::once(fact.frame_id.clone()))
        .chain(
            fact.variables
                .iter()
                .map(|variable| variable.variable_id.clone()),
        )
        .chain(
            fact.variables
                .iter()
                .flat_map(|variable| variable.evidence_ids.iter().cloned()),
        )
        .chain(
            fact.variables
                .iter()
                .filter_map(|variable| variable.data_type_id.clone()),
        )
        .collect::<BTreeSet<_>>()
        .into_iter()
        .collect::<Vec<_>>();
    Some(StackFrameContract {
        contract_id: fact.frame_id.trim().to_string(),
        function_id: fact.function_id.clone(),
        artifact_id: load.artifact.artifact_id.clone(),
        address,
        frame_size: fact.frame_size,
        local_size: fact.local_size,
        parameter_size: fact.parameter_size,
        parameter_offset: fact.parameter_offset,
        return_address_offset: fact.return_address_offset,
        growth: stack_frame_growth_from_ghidra(&fact.growth),
        stack_pointer_register: fact.stack_pointer_register.clone(),
        custom_variable_storage: fact.custom_variable_storage,
        variables,
        confidence: 0.93,
        evidence,
        authority: "observed_fact".to_string(),
    })
}

