fn stack_frame_growth_from_ghidra(growth: &str) -> StackFrameGrowth {
    match growth
        .trim()
        .to_ascii_lowercase()
        .replace('-', "_")
        .as_str()
    {
        "negative" | "grows_negative" | "down" | "downward" => StackFrameGrowth::Negative,
        "positive" | "grows_positive" | "up" | "upward" => StackFrameGrowth::Positive,
        _ => StackFrameGrowth::Unknown,
    }
}

fn stack_frame_variable_kind_from_ghidra(kind: &str) -> StackFrameVariableKind {
    match kind.trim().to_ascii_lowercase().replace('-', "_").as_str() {
        "parameter" | "param" => StackFrameVariableKind::Parameter,
        "local" | "stack" => StackFrameVariableKind::Local,
        "save_area" | "savearea" | "saved_register" | "savedregister" => {
            StackFrameVariableKind::SaveArea
        }
        "return_address" | "returnaddress" => StackFrameVariableKind::ReturnAddress,
        _ => StackFrameVariableKind::Unknown,
    }
}

fn prototype_data_type_from_ghidra_stack_variable(
    fact: &GhidraOracleStackFrameVariableFact,
) -> PrototypeDataType {
    let display_name = fact.data_type.trim();
    let display_name = if display_name.is_empty() {
        "unknown"
    } else {
        display_name
    };
    let kind = if display_name.contains('*') {
        "pointer"
    } else if display_name.starts_with("struct ") {
        "structure"
    } else if display_name.starts_with("enum ") {
        "enum"
    } else if display_name == "void" {
        "void"
    } else {
        "external"
    };
    PrototypeDataType {
        name: display_name.to_string(),
        display_name: display_name.to_string(),
        byte_len: (fact.byte_len > 0).then_some(fact.byte_len),
        kind: kind.to_string(),
    }
}

