fn parameter_measure_io_from_ghidra(io: &str) -> ParameterMeasureIo {
    match io.trim().to_ascii_lowercase().replace('-', "_").as_str() {
        "output" | "out" | "return" | "retval" | "return_value" => ParameterMeasureIo::Output,
        _ => ParameterMeasureIo::Input,
    }
}

fn parameter_measure_rank_from_ghidra(rank: &str) -> ParameterMeasureRank {
    match rank.trim().to_ascii_lowercase().replace('-', "_").as_str() {
        "direct_write_without_read" | "directwritewithoutread" | "direct_write_no_read" => {
            ParameterMeasureRank::DirectWriteWithoutRead
        }
        "direct_read" | "directread" => ParameterMeasureRank::DirectRead,
        "direct_write_with_read" | "directwritewithread" => {
            ParameterMeasureRank::DirectWriteWithRead
        }
        "direct_write_unknown_read" | "directwriteunknownread" => {
            ParameterMeasureRank::DirectWriteUnknownRead
        }
        "sub_function_parameter" | "subfunctionparameter" | "sub_param" => {
            ParameterMeasureRank::SubFunctionParameter
        }
        "this_function_parameter" | "thisfunctionparameter" | "this_param" | "parameter" => {
            ParameterMeasureRank::ThisFunctionParameter
        }
        "sub_function_return" | "subfunctionreturn" | "sub_return" => {
            ParameterMeasureRank::SubFunctionReturn
        }
        "this_function_return" | "thisfunctionreturn" | "return" => {
            ParameterMeasureRank::ThisFunctionReturn
        }
        "indirect" => ParameterMeasureRank::Indirect,
        "worst_rank" | "worstrank" => ParameterMeasureRank::WorstRank,
        _ => ParameterMeasureRank::Unknown,
    }
}

fn prototype_data_type_from_ghidra_parameter_measure(
    fact: &GhidraOracleParameterMeasureFact,
) -> PrototypeDataType {
    let display_name = fact.data_type.trim();
    let display_name = if display_name.is_empty() {
        "unknown"
    } else {
        display_name
    };
    let byte_len = (fact.storage.byte_len > 0).then_some(fact.storage.byte_len);
    let kind = if display_name.contains('*') {
        "pointer"
    } else if display_name.starts_with("struct ") {
        "structure"
    } else if display_name.starts_with("enum ") {
        "enum"
    } else if display_name == "void" {
        "void"
    } else {
        "external"
    };
    PrototypeDataType {
        name: display_name.to_string(),
        display_name: display_name.to_string(),
        byte_len,
        kind: kind.to_string(),
    }
}

