fn normalize_decompiler_diagnostic_contracts(
    load: &BinaryLoadReport,
    program: &ThirProgram,
    contracts: &[DecompilerDiagnosticContract],
) -> Vec<DecompilerDiagnosticContract> {
    let mut normalized = contracts
        .iter()
        .map(|contract| {
            let function_id = contract
                .function_id
                .as_deref()
                .map(str::trim)
                .filter(|function_id| !function_id.is_empty())
                .map(ToOwned::to_owned)
                .or_else(|| {
                    contract.address.and_then(|address| {
                        function_for_address(program, address)
                            .map(|function| function.function_id.clone())
                    })
                });
            let artifact_id = if contract.artifact_id.trim().is_empty() {
                load.artifact.artifact_id.clone()
            } else {
                contract.artifact_id.trim().to_string()
            };
            let message = if contract.message.trim().is_empty() {
                "Unknown decompiler diagnostic".to_string()
            } else {
                contract.message.trim().to_string()
            };
            let mut normalized_contract = DecompilerDiagnosticContract {
                contract_id: contract.contract_id.trim().to_string(),
                function_id,
                artifact_id,
                address: contract.address,
                category: contract.category.clone(),
                severity: contract.severity.clone(),
                placement: contract.placement.clone(),
                message,
                source_pass: normalize_optional_id(contract.source_pass.as_deref()),
                source_rule: normalize_optional_id(contract.source_rule.as_deref()),
                affects_control_flow: contract.affects_control_flow,
                affects_prototype: contract.affects_prototype,
                affects_data_flow: contract.affects_data_flow,
                remediation: normalize_optional_id(contract.remediation.as_deref()),
                confidence: normalize_confidence(contract.confidence),
                evidence: normalize_id_list(&contract.evidence),
                authority: if contract.authority.trim().is_empty() {
                    "derived_fact".to_string()
                } else {
                    contract.authority.trim().to_string()
                },
            };
            if normalized_contract.contract_id.is_empty() {
                normalized_contract.contract_id = format!(
                    "recon:decompiler_diagnostic_contract:{}",
                    decompiler_diagnostic_fingerprint(&normalized_contract)
                );
            }
            normalized_contract
        })
        .collect::<Vec<_>>();
    normalized.sort_by(|left, right| {
        left.function_id
            .cmp(&right.function_id)
            .then_with(|| left.address.cmp(&right.address))
            .then_with(|| left.contract_id.cmp(&right.contract_id))
    });
    normalized.dedup_by(|left, right| left.contract_id == right.contract_id);
    normalized
}

