fn compile_reconstruction_plan_with_all_contracts(
    load: &BinaryLoadReport,
    components: &[ComponentHypothesis],
    roles: &[SemanticRole],
    signatures: &[FunctionSemanticSignature],
    prototype_contracts: &[FunctionPrototypeContract],
    data_type_contracts: &[DataTypeContract],
    data_type_dependency_plan: &DataTypeDependencyPlan,
    structure_field_access_contracts: &[StructureFieldAccessContract],
    high_variable_contracts: &[HighVariableContract],
    parameter_measure_contracts: &[ParameterMeasureContract],
    pcode_inject_contracts: &[PcodeInjectContract],
    flow_override_contracts: &[FlowOverrideContract],
    variable_merge_contracts: &[VariableMergeContract],
    decompiler_rule_contracts: &[DecompilerRuleApplicationContract],
    jump_table_contracts: &[JumpTableContract],
    equate_contracts: &[EquateContract],
    external_linkage_contracts: &[ExternalLinkageContract],
    program: &ThirProgram,
) -> ReconstructionPlan {
    let prototype_contracts = normalize_function_prototype_contracts(program, prototype_contracts);
    let data_type_contracts = normalize_data_type_contracts(load, data_type_contracts);
    let structure_field_access_contracts =
        normalize_structure_field_access_contracts(load, program, structure_field_access_contracts);
    let high_variable_contracts =
        normalize_high_variable_contracts(load, program, high_variable_contracts);
    let parameter_measure_contracts =
        normalize_parameter_measure_contracts(load, program, parameter_measure_contracts);
    let pcode_inject_contracts =
        normalize_pcode_inject_contracts(load, program, pcode_inject_contracts);
    let flow_override_contracts =
        normalize_flow_override_contracts(load, program, flow_override_contracts);
    let variable_merge_contracts =
        normalize_variable_merge_contracts(load, program, variable_merge_contracts);
    let decompiler_rule_contracts =
        normalize_decompiler_rule_contracts(load, program, decompiler_rule_contracts);
    let jump_table_contracts = normalize_jump_table_contracts(load, program, jump_table_contracts);
    let equate_contracts = normalize_equate_contracts(load, program, equate_contracts);
    let external_linkage_contracts =
        normalize_external_linkage_contracts(load, program, external_linkage_contracts);
    let roles_by_id = roles
        .iter()
        .map(|role| (role.role_id.clone(), role))
        .collect::<BTreeMap<_, _>>();
    let signature_by_function = signatures
        .iter()
        .map(|signature| (signature.function_id.as_str(), signature))
        .collect::<BTreeMap<_, _>>();
    let contracts_by_function = prototype_contracts_by_function(program, &prototype_contracts);
    let structure_field_accesses_by_function =
        structure_field_access_contracts_by_function(program, &structure_field_access_contracts);
    let high_variables_by_function =
        high_variable_contracts_by_function(program, &high_variable_contracts);
    let parameter_measures_by_function =
        parameter_measure_contracts_by_function(program, &parameter_measure_contracts);
    let pcode_injects_by_function =
        pcode_inject_contracts_by_function(program, &pcode_inject_contracts);
    let flow_overrides_by_function =
        flow_override_contracts_by_function(program, &flow_override_contracts);
    let variable_merges_by_function =
        variable_merge_contracts_by_function(program, &variable_merge_contracts);
    let decompiler_rules_by_function =
        decompiler_rule_contracts_by_function(program, &decompiler_rule_contracts);
    let jump_tables_by_function = jump_table_contracts_by_function(program, &jump_table_contracts);
    let equates_by_function = equate_contracts_by_function(program, &equate_contracts);
    let external_linkages_by_function =
        external_linkage_contracts_by_function(program, &external_linkage_contracts);
    let instructions = components
        .iter()
        .map(|component| {
            let component_roles = component
                .role_ids
                .iter()
                .filter_map(|role_id| roles_by_id.get(role_id).copied())
                .collect::<Vec<_>>();
            let component_signatures = component
                .function_ids
                .iter()
                .filter_map(|function_id| signature_by_function.get(function_id.as_str()).copied())
                .collect::<Vec<_>>();
            let component_prototype_contracts = component
                .function_ids
                .iter()
                .flat_map(|function_id| {
                    contracts_by_function
                        .get(function_id)
                        .into_iter()
                        .flat_map(|contracts| contracts.iter().copied())
                })
                .collect::<Vec<_>>();
            let component_data_type_contracts = data_type_contracts_for_prototypes(
                &component_prototype_contracts,
                &data_type_contracts,
                data_type_dependency_plan,
            );
            let component_structure_field_access_contracts = component
                .function_ids
                .iter()
                .flat_map(|function_id| {
                    structure_field_accesses_by_function
                        .get(function_id)
                        .into_iter()
                        .flat_map(|contracts| contracts.iter().copied())
                })
                .collect::<Vec<_>>();
            let component_high_variable_contracts = component
                .function_ids
                .iter()
                .flat_map(|function_id| {
                    high_variables_by_function
                        .get(function_id)
                        .into_iter()
                        .flat_map(|contracts| contracts.iter().copied())
                })
                .collect::<Vec<_>>();
            let component_parameter_measure_contracts = component
                .function_ids
                .iter()
                .flat_map(|function_id| {
                    parameter_measures_by_function
                        .get(function_id)
                        .into_iter()
                        .flat_map(|contracts| contracts.iter().copied())
                })
                .collect::<Vec<_>>();
            let component_pcode_inject_contracts = component
                .function_ids
                .iter()
                .flat_map(|function_id| {
                    pcode_injects_by_function
                        .get(function_id)
                        .into_iter()
                        .flat_map(|contracts| contracts.iter().copied())
                })
                .collect::<Vec<_>>();
            let component_flow_override_contracts = component
                .function_ids
                .iter()
                .flat_map(|function_id| {
                    flow_overrides_by_function
                        .get(function_id)
                        .into_iter()
                        .flat_map(|contracts| contracts.iter().copied())
                })
                .collect::<Vec<_>>();
            let component_variable_merge_contracts = component
                .function_ids
                .iter()
                .flat_map(|function_id| {
                    variable_merges_by_function
                        .get(function_id)
                        .into_iter()
                        .flat_map(|contracts| contracts.iter().copied())
                })
                .collect::<Vec<_>>();
            let component_decompiler_rule_contracts = component
                .function_ids
                .iter()
                .flat_map(|function_id| {
                    decompiler_rules_by_function
                        .get(function_id)
                        .into_iter()
                        .flat_map(|contracts| contracts.iter().copied())
                })
                .collect::<Vec<_>>();
            let component_jump_table_contracts = component
                .function_ids
                .iter()
                .flat_map(|function_id| {
                    jump_tables_by_function
                        .get(function_id)
                        .into_iter()
                        .flat_map(|contracts| contracts.iter().copied())
                })
                .collect::<Vec<_>>();
            let component_equate_contracts = component
                .function_ids
                .iter()
                .flat_map(|function_id| {
                    equates_by_function
                        .get(function_id)
                        .into_iter()
                        .flat_map(|contracts| contracts.iter().copied())
                })
                .collect::<Vec<_>>();
            let component_external_linkage_contracts = component
                .function_ids
                .iter()
                .flat_map(|function_id| {
                    external_linkages_by_function
                        .get(function_id)
                        .into_iter()
                        .flat_map(|contracts| contracts.iter().copied())
                })
                .collect::<Vec<_>>();
            instruction_for_component(
                load,
                component,
                &component_roles,
                &component_signatures,
                &component_prototype_contracts,
                &component_data_type_contracts,
                &component_structure_field_access_contracts,
                &component_high_variable_contracts,
                &component_parameter_measure_contracts,
                &component_pcode_inject_contracts,
                &component_flow_override_contracts,
                &component_variable_merge_contracts,
                &component_decompiler_rule_contracts,
                &component_jump_table_contracts,
                &component_equate_contracts,
                &component_external_linkage_contracts,
                program,
            )
        })
        .collect::<Vec<_>>();
    let confidence = if instructions.is_empty() {
        0.0
    } else {
        instructions
            .iter()
            .map(|instruction| instruction.confidence)
            .sum::<f64>()
            / instructions.len() as f64
    };
    ReconstructionPlan {
        plan_id: format!(
            "recon:plan:{}",
            stable_hash(json!([&load.artifact.artifact_id, instructions.len()]))
        ),
        source_artifact: load.artifact.artifact_id.clone(),
        instructions,
        confidence,
    }
}

pub fn write_reconstruction_analysis_in_store<S: GraphStore>(
    store: &mut S,
    analysis: &ReconstructionAnalysis,
) -> GraphStoreResult<()> {
    write_reconstruction_analysis_in_store_scoped(store, analysis, None)
}

