fn write_function_prototype_contracts_in_store_scoped<S: GraphStore>(
    store: &mut S,
    contracts: &[FunctionPrototypeContract],
    tenant_id: Option<&str>,
) -> GraphStoreResult<()> {
    for contract in contracts {
        let contract_id = graph_id(&contract.contract_id, tenant_id);
        store.upsert_node(prototype_contract_node(contract, tenant_id))?;
        if let Some(function_id) = &contract.function_id {
            store.upsert_edge(EdgeRecord::new(
                graph_edge_id(
                    function_id,
                    FUNCTION_HAS_PROTOTYPE_CONTRACT,
                    &contract_id,
                    tenant_id,
                ),
                function_id,
                FUNCTION_HAS_PROTOTYPE_CONTRACT,
                &contract_id,
                provenance_props(&contract.authority, tenant_id),
            ))?;
        }
        for evidence_id in &contract.evidence {
            let evidence_id = evidence_graph_id(evidence_id, tenant_id);
            store.upsert_edge(EdgeRecord::new(
                graph_edge_id(
                    &contract_id,
                    PROTOTYPE_CONTRACT_EVIDENCED_BY,
                    &evidence_id,
                    tenant_id,
                ),
                &contract_id,
                PROTOTYPE_CONTRACT_EVIDENCED_BY,
                &evidence_id,
                provenance_props(&contract.authority, tenant_id),
            ))?;
        }
    }
    Ok(())
}

fn write_data_type_contracts_in_store_scoped<S: GraphStore>(
    store: &mut S,
    contracts: &[DataTypeContract],
    plan: &DataTypeDependencyPlan,
    tenant_id: Option<&str>,
) -> GraphStoreResult<()> {
    let contracts_by_type = contracts
        .iter()
        .map(|contract| (contract.type_id.as_str(), contract))
        .collect::<BTreeMap<_, _>>();
    store.upsert_node(data_type_dependency_plan_node(plan, tenant_id))?;
    let plan_id = graph_id(&plan.plan_id, tenant_id);
    for contract in contracts {
        let contract_id = graph_id(&contract.contract_id, tenant_id);
        store.upsert_node(data_type_contract_node(contract, tenant_id))?;
        store.upsert_edge(EdgeRecord::new(
            graph_edge_id(&plan_id, DATA_TYPE_PLAN_HAS_TYPE, &contract_id, tenant_id),
            &plan_id,
            DATA_TYPE_PLAN_HAS_TYPE,
            &contract_id,
            provenance_props(&plan.authority, tenant_id),
        ))?;
        for evidence_id in &contract.evidence {
            let evidence_id = evidence_graph_id(evidence_id, tenant_id);
            store.upsert_edge(EdgeRecord::new(
                graph_edge_id(
                    &contract_id,
                    DATA_TYPE_CONTRACT_EVIDENCED_BY,
                    &evidence_id,
                    tenant_id,
                ),
                &contract_id,
                DATA_TYPE_CONTRACT_EVIDENCED_BY,
                &evidence_id,
                provenance_props(&contract.authority, tenant_id),
            ))?;
        }
    }
    for edge in &plan.hard_dependency_edges {
        let Some(dependent) = contracts_by_type.get(edge.dependent_type_id.as_str()) else {
            continue;
        };
        let to_id = contracts_by_type
            .get(edge.dependency_type_id.as_str())
            .map(|contract| contract.contract_id.as_str())
            .unwrap_or(edge.dependency_type_id.as_str());
        let from_id = graph_id(&dependent.contract_id, tenant_id);
        let to_id = evidence_graph_id(to_id, tenant_id);
        store.upsert_edge(EdgeRecord::new(
            graph_edge_id(&from_id, DATA_TYPE_DEPENDS_ON, &to_id, tenant_id),
            &from_id,
            DATA_TYPE_DEPENDS_ON,
            &to_id,
            provenance_props(&dependent.authority, tenant_id),
        ))?;
    }
    for edge in &plan.soft_dependency_edges {
        let Some(dependent) = contracts_by_type.get(edge.dependent_type_id.as_str()) else {
            continue;
        };
        let to_id = contracts_by_type
            .get(edge.dependency_type_id.as_str())
            .map(|contract| contract.contract_id.as_str())
            .unwrap_or(edge.dependency_type_id.as_str());
        let from_id = graph_id(&dependent.contract_id, tenant_id);
        let to_id = evidence_graph_id(to_id, tenant_id);
        store.upsert_edge(EdgeRecord::new(
            graph_edge_id(&from_id, DATA_TYPE_SOFT_DEPENDS_ON, &to_id, tenant_id),
            &from_id,
            DATA_TYPE_SOFT_DEPENDS_ON,
            &to_id,
            provenance_props(&dependent.authority, tenant_id),
        ))?;
    }
    Ok(())
}

fn write_structure_field_access_contracts_in_store_scoped<S: GraphStore>(
    store: &mut S,
    contracts: &[StructureFieldAccessContract],
    tenant_id: Option<&str>,
) -> GraphStoreResult<()> {
    for contract in contracts {
        let contract_id = graph_id(&contract.contract_id, tenant_id);
        store.upsert_node(structure_field_access_contract_node(contract, tenant_id))?;
        if let Some(function_id) = &contract.function_id {
            store.upsert_edge(EdgeRecord::new(
                graph_edge_id(
                    function_id,
                    FUNCTION_HAS_STRUCTURE_FIELD_ACCESS,
                    &contract_id,
                    tenant_id,
                ),
                function_id,
                FUNCTION_HAS_STRUCTURE_FIELD_ACCESS,
                &contract_id,
                provenance_props(&contract.authority, tenant_id),
            ))?;
        }
        let structure_type_id = graph_id(&contract.structure_type_id, tenant_id);
        if store.get_node(&structure_type_id).is_none() {
            store.upsert_node(NodeRecord::new(
                &structure_type_id,
                ["DataTypeReference"],
                stamp_scoped_record(
                    json!({
                        "artifact_id": &contract.artifact_id,
                        "type_id": &contract.structure_type_id,
                        "name": &contract.structure_name,
                        "authority": &contract.authority,
                        "source": RECONSTRUCT_SOURCE,
                        "version": RECONSTRUCT_VERSION,
                    }),
                    &contract.structure_type_id,
                    tenant_id,
                ),
            ))?;
        }
        store.upsert_edge(EdgeRecord::new(
            graph_edge_id(
                &contract_id,
                STRUCTURE_FIELD_ACCESS_USES_DATA_TYPE,
                &structure_type_id,
                tenant_id,
            ),
            &contract_id,
            STRUCTURE_FIELD_ACCESS_USES_DATA_TYPE,
            &structure_type_id,
            provenance_props(&contract.authority, tenant_id),
        ))?;
        for evidence_id in structure_field_access_evidence_ids(contract) {
            let evidence_id = evidence_graph_id(&evidence_id, tenant_id);
            store.upsert_edge(EdgeRecord::new(
                graph_edge_id(
                    &contract_id,
                    STRUCTURE_FIELD_ACCESS_EVIDENCED_BY,
                    &evidence_id,
                    tenant_id,
                ),
                &contract_id,
                STRUCTURE_FIELD_ACCESS_EVIDENCED_BY,
                &evidence_id,
                provenance_props(&contract.authority, tenant_id),
            ))?;
        }
    }
    Ok(())
}

fn write_stack_frame_contracts_in_store_scoped<S: GraphStore>(
    store: &mut S,
    contracts: &[StackFrameContract],
    tenant_id: Option<&str>,
) -> GraphStoreResult<()> {
    for contract in contracts {
        let contract_id = graph_id(&contract.contract_id, tenant_id);
        store.upsert_node(stack_frame_contract_node(contract, tenant_id))?;
        if let Some(function_id) = &contract.function_id {
            store.upsert_edge(EdgeRecord::new(
                graph_edge_id(
                    function_id,
                    FUNCTION_HAS_STACK_FRAME_CONTRACT,
                    &contract_id,
                    tenant_id,
                ),
                function_id,
                FUNCTION_HAS_STACK_FRAME_CONTRACT,
                &contract_id,
                provenance_props(&contract.authority, tenant_id),
            ))?;
        }
        for variable in &contract.variables {
            let variable_id = graph_id(&variable.variable_id, tenant_id);
            store.upsert_node(stack_frame_variable_node(contract, variable, tenant_id))?;
            store.upsert_edge(EdgeRecord::new(
                graph_edge_id(
                    &contract_id,
                    STACK_FRAME_HAS_VARIABLE,
                    &variable_id,
                    tenant_id,
                ),
                &contract_id,
                STACK_FRAME_HAS_VARIABLE,
                &variable_id,
                provenance_props(&contract.authority, tenant_id),
            ))?;
            if let Some(data_type_id) = &variable.data_type_id {
                let data_type_id = graph_id(data_type_id, tenant_id);
                if store.get_node(&data_type_id).is_none() {
                    store.upsert_node(NodeRecord::new(
                        &data_type_id,
                        ["DataTypeReference"],
                        stamp_scoped_record(
                            json!({
                                "artifact_id": &contract.artifact_id,
                                "type_id": data_type_id,
                                "name": &variable.data_type.display_name,
                                "authority": &contract.authority,
                                "source": RECONSTRUCT_SOURCE,
                                "version": RECONSTRUCT_VERSION,
                            }),
                            variable.data_type_id.as_deref().unwrap_or_default(),
                            tenant_id,
                        ),
                    ))?;
                }
                store.upsert_edge(EdgeRecord::new(
                    graph_edge_id(
                        &variable_id,
                        STACK_FRAME_VARIABLE_USES_DATA_TYPE,
                        &data_type_id,
                        tenant_id,
                    ),
                    &variable_id,
                    STACK_FRAME_VARIABLE_USES_DATA_TYPE,
                    &data_type_id,
                    provenance_props(&contract.authority, tenant_id),
                ))?;
            }
        }
        for evidence_id in stack_frame_evidence_ids(contract) {
            let evidence_id = evidence_graph_id(&evidence_id, tenant_id);
            store.upsert_edge(EdgeRecord::new(
                graph_edge_id(
                    &contract_id,
                    STACK_FRAME_EVIDENCED_BY,
                    &evidence_id,
                    tenant_id,
                ),
                &contract_id,
                STACK_FRAME_EVIDENCED_BY,
                &evidence_id,
                provenance_props(&contract.authority, tenant_id),
            ))?;
        }
    }
    Ok(())
}

