fn write_pcode_execution_contracts_in_store_scoped<S: GraphStore>(
    store: &mut S,
    contracts: &[PcodeExecutionContract],
    tenant_id: Option<&str>,
) -> GraphStoreResult<()> {
    for contract in contracts {
        let contract_id = graph_id(&contract.contract_id, tenant_id);
        store.upsert_node(pcode_execution_contract_node(contract, tenant_id))?;
        if let Some(function_id) = &contract.function_id {
            store.upsert_edge(EdgeRecord::new(
                graph_edge_id(
                    function_id,
                    FUNCTION_HAS_PCODE_EXECUTION_CONTRACT,
                    &contract_id,
                    tenant_id,
                ),
                function_id,
                FUNCTION_HAS_PCODE_EXECUTION_CONTRACT,
                &contract_id,
                provenance_props(&contract.authority, tenant_id),
            ))?;
        }
        for observation in contract
            .initial_observations
            .iter()
            .chain(contract.final_observations.iter())
        {
            let observation_id = graph_id(&observation.observation_id, tenant_id);
            store.upsert_node(pcode_execution_observation_node(
                contract,
                observation,
                tenant_id,
            ))?;
            store.upsert_edge(EdgeRecord::new(
                graph_edge_id(
                    &contract_id,
                    PCODE_EXECUTION_HAS_OBSERVATION,
                    &observation_id,
                    tenant_id,
                ),
                &contract_id,
                PCODE_EXECUTION_HAS_OBSERVATION,
                &observation_id,
                provenance_props(&contract.authority, tenant_id),
            ))?;
        }
        for flow in &contract.taint_flows {
            let flow_id = graph_id(&flow.flow_id, tenant_id);
            store.upsert_node(pcode_taint_flow_node(contract, flow, tenant_id))?;
            store.upsert_edge(EdgeRecord::new(
                graph_edge_id(
                    &contract_id,
                    PCODE_EXECUTION_HAS_TAINT_FLOW,
                    &flow_id,
                    tenant_id,
                ),
                &contract_id,
                PCODE_EXECUTION_HAS_TAINT_FLOW,
                &flow_id,
                provenance_props(&contract.authority, tenant_id),
            ))?;
        }
        for precondition in &contract.symbolic_preconditions {
            let precondition_id = graph_id(&precondition.precondition_id, tenant_id);
            store.upsert_node(pcode_symbolic_precondition_node(
                contract,
                precondition,
                tenant_id,
            ))?;
            store.upsert_edge(EdgeRecord::new(
                graph_edge_id(
                    &contract_id,
                    PCODE_EXECUTION_HAS_PRECONDITION,
                    &precondition_id,
                    tenant_id,
                ),
                &contract_id,
                PCODE_EXECUTION_HAS_PRECONDITION,
                &precondition_id,
                provenance_props(&contract.authority, tenant_id),
            ))?;
        }
        for value in &contract.symbolic_values {
            let value_id = graph_id(&value.value_id, tenant_id);
            store.upsert_node(pcode_symbolic_value_node(contract, value, tenant_id))?;
            store.upsert_edge(EdgeRecord::new(
                graph_edge_id(
                    &contract_id,
                    PCODE_EXECUTION_HAS_SYMBOLIC_VALUE,
                    &value_id,
                    tenant_id,
                ),
                &contract_id,
                PCODE_EXECUTION_HAS_SYMBOLIC_VALUE,
                &value_id,
                provenance_props(&contract.authority, tenant_id),
            ))?;
        }
        if let Some(state) = &contract.symbolic_state {
            let state_id = graph_id(&state.summary_id, tenant_id);
            store.upsert_node(pcode_symbolic_state_node(contract, state, tenant_id))?;
            store.upsert_edge(EdgeRecord::new(
                graph_edge_id(
                    &contract_id,
                    PCODE_EXECUTION_HAS_SYMBOLIC_STATE,
                    &state_id,
                    tenant_id,
                ),
                &contract_id,
                PCODE_EXECUTION_HAS_SYMBOLIC_STATE,
                &state_id,
                provenance_props(&contract.authority, tenant_id),
            ))?;
            for witness in &state.memory_witnesses {
                let witness_id = graph_id(&witness.witness_id, tenant_id);
                store.upsert_node(pcode_memory_witness_node(
                    contract, state, witness, tenant_id,
                ))?;
                store.upsert_edge(EdgeRecord::new(
                    graph_edge_id(
                        &state_id,
                        PCODE_SYMBOLIC_STATE_HAS_MEMORY_WITNESS,
                        &witness_id,
                        tenant_id,
                    ),
                    &state_id,
                    PCODE_SYMBOLIC_STATE_HAS_MEMORY_WITNESS,
                    &witness_id,
                    provenance_props(&contract.authority, tenant_id),
                ))?;
            }
        }
        for evidence_id in pcode_execution_contract_evidence_ids(contract) {
            let evidence_id = evidence_graph_id(&evidence_id, tenant_id);
            store.upsert_edge(EdgeRecord::new(
                graph_edge_id(
                    &contract_id,
                    PCODE_EXECUTION_EVIDENCED_BY,
                    &evidence_id,
                    tenant_id,
                ),
                &contract_id,
                PCODE_EXECUTION_EVIDENCED_BY,
                &evidence_id,
                provenance_props(&contract.authority, tenant_id),
            ))?;
        }
    }
    Ok(())
}

