fn write_function_hash_families_in_store_scoped<S: GraphStore>(
    store: &mut S,
    families: &[FunctionHashFamily],
    tenant_id: Option<&str>,
) -> GraphStoreResult<()> {
    for family in families {
        let family_id = graph_id(&family.family_id, tenant_id);
        let signature_id = graph_id(&family.signature_id, tenant_id);
        store.upsert_node(hash_family_node(family, tenant_id))?;
        store.upsert_edge(EdgeRecord::new(
            graph_edge_id(
                &family_id,
                HASH_FAMILY_FOR_SIGNATURE,
                &signature_id,
                tenant_id,
            ),
            &family_id,
            HASH_FAMILY_FOR_SIGNATURE,
            &signature_id,
            provenance_props(&family.authority, tenant_id),
        ))?;
        for parent_id in &family.parent_signature_ids {
            let parent_id = graph_id(parent_id, tenant_id);
            store.upsert_edge(EdgeRecord::new(
                graph_edge_id(
                    &family_id,
                    HASH_FAMILY_HAS_PARENT_SIGNATURE,
                    &parent_id,
                    tenant_id,
                ),
                &family_id,
                HASH_FAMILY_HAS_PARENT_SIGNATURE,
                &parent_id,
                provenance_props(&family.authority, tenant_id),
            ))?;
        }
        for child_id in &family.child_signature_ids {
            let child_id = graph_id(child_id, tenant_id);
            store.upsert_edge(EdgeRecord::new(
                graph_edge_id(
                    &family_id,
                    HASH_FAMILY_HAS_CHILD_SIGNATURE,
                    &child_id,
                    tenant_id,
                ),
                &family_id,
                HASH_FAMILY_HAS_CHILD_SIGNATURE,
                &child_id,
                provenance_props(&family.authority, tenant_id),
            ))?;
        }
    }
    Ok(())
}

pub fn write_function_semantic_matches_in_store<S: GraphStore>(
    store: &mut S,
    matches: &[FunctionSemanticMatch],
) -> GraphStoreResult<()> {
    write_function_semantic_matches_in_store_scoped(store, matches, None)
}

pub fn write_function_semantic_matches_in_store_for_tenant<S: GraphStore>(
    store: &mut S,
    matches: &[FunctionSemanticMatch],
    tenant_id: &str,
) -> GraphStoreResult<()> {
    write_function_semantic_matches_in_store_scoped(store, matches, Some(tenant_id))
}

fn write_function_semantic_matches_in_store_scoped<S: GraphStore>(
    store: &mut S,
    matches: &[FunctionSemanticMatch],
    tenant_id: Option<&str>,
) -> GraphStoreResult<()> {
    for function_match in matches {
        let match_id = graph_id(&function_match.match_id, tenant_id);
        let source_signature_id = graph_id(&function_match.source_signature_id, tenant_id);
        let destination_signature_id =
            graph_id(&function_match.destination_signature_id, tenant_id);
        store.upsert_node(function_match_node(function_match, tenant_id))?;
        for (edge_type, target_id) in [
            (MATCH_SOURCE_SIGNATURE, source_signature_id.as_str()),
            (
                MATCH_DESTINATION_SIGNATURE,
                destination_signature_id.as_str(),
            ),
            (
                MATCH_SOURCE_FUNCTION,
                function_match.source_function_id.as_str(),
            ),
            (
                MATCH_DESTINATION_FUNCTION,
                function_match.destination_function_id.as_str(),
            ),
        ] {
            store.upsert_edge(EdgeRecord::new(
                graph_edge_id(&match_id, edge_type, target_id, tenant_id),
                &match_id,
                edge_type,
                target_id,
                provenance_props(&function_match.authority, tenant_id),
            ))?;
        }
    }
    Ok(())
}

