fn write_function_match_review_receipts_in_store_scoped<S: GraphStore>(
    store: &mut S,
    match_sets: &[FunctionMatchSet],
    markup_items: &[FunctionMatchMarkupItem],
    receipts: &[FunctionMatchReviewReceipt],
    tenant_id: Option<&str>,
) -> GraphStoreResult<()> {
    for match_set in match_sets {
        let match_set_id = graph_id(&match_set.match_set_id, tenant_id);
        store.upsert_node(function_match_set_node(match_set, tenant_id))?;
        for match_id in match_set.match_ids.iter().collect::<BTreeSet<_>>() {
            let match_id = graph_id(match_id, tenant_id);
            store.upsert_edge(EdgeRecord::new(
                graph_edge_id(&match_set_id, MATCH_SET_HAS_MATCH, &match_id, tenant_id),
                &match_set_id,
                MATCH_SET_HAS_MATCH,
                &match_id,
                provenance_props(&match_set.authority, tenant_id),
            ))?;
        }
    }

    for item in markup_items {
        let item_id = graph_id(&item.item_id, tenant_id);
        let match_id = graph_id(&item.match_id, tenant_id);
        store.upsert_node(function_match_markup_item_node(item, tenant_id))?;
        store.upsert_edge(EdgeRecord::new(
            graph_edge_id(&match_id, MATCH_HAS_MARKUP_ITEM, &item_id, tenant_id),
            &match_id,
            MATCH_HAS_MARKUP_ITEM,
            &item_id,
            provenance_props(&item.authority, tenant_id),
        ))?;
    }

    for receipt in receipts {
        let receipt_id = graph_id(&receipt.receipt_id, tenant_id);
        let match_id = graph_id(&receipt.match_id, tenant_id);
        store.upsert_node(function_match_review_receipt_node(receipt, tenant_id))?;
        store.upsert_edge(EdgeRecord::new(
            graph_edge_id(&match_id, MATCH_HAS_REVIEW_RECEIPT, &receipt_id, tenant_id),
            &match_id,
            MATCH_HAS_REVIEW_RECEIPT,
            &receipt_id,
            provenance_props(&receipt.authority, tenant_id),
        ))?;
        if let Some(match_set_id) = &receipt.match_set_id {
            let match_set_id = graph_id(match_set_id, tenant_id);
            store.upsert_edge(EdgeRecord::new(
                graph_edge_id(
                    &match_set_id,
                    MATCH_SET_HAS_REVIEW_RECEIPT,
                    &receipt_id,
                    tenant_id,
                ),
                &match_set_id,
                MATCH_SET_HAS_REVIEW_RECEIPT,
                &receipt_id,
                provenance_props(&receipt.authority, tenant_id),
            ))?;
        }
        for item_id in receipt.item_ids.iter().collect::<BTreeSet<_>>() {
            let item_id = graph_id(item_id, tenant_id);
            store.upsert_edge(EdgeRecord::new(
                graph_edge_id(
                    &receipt_id,
                    REVIEW_RECEIPT_COVERS_MARKUP_ITEM,
                    &item_id,
                    tenant_id,
                ),
                &receipt_id,
                REVIEW_RECEIPT_COVERS_MARKUP_ITEM,
                &item_id,
                provenance_props(&receipt.authority, tenant_id),
            ))?;
        }
    }
    Ok(())
}

