fn evidence_by_function_and_role(
    load: &BinaryLoadReport,
    program: &ThirProgram,
) -> BTreeMap<String, BTreeMap<SemanticRoleKind, Vec<String>>> {
    let mut map = BTreeMap::<String, BTreeMap<SemanticRoleKind, BTreeSet<String>>>::new();
    for string in &load.strings {
        if let Some(function) = single_function_owner(program) {
            for role in roles_for_string(string) {
                map.entry(function.function_id.clone())
                    .or_default()
                    .entry(role)
                    .or_default()
                    .insert(string.string_id.clone());
            }
        }
    }
    for symbol in &load.symbols {
        let name = symbol.name.to_ascii_lowercase();
        let role = if name.contains("sqlite3_") || name.contains("postgres") {
            Some(SemanticRoleKind::DatabaseAccess)
        } else if name.contains("ssl") || name.contains("crypto") || name.contains("sha") {
            Some(SemanticRoleKind::CryptoWrapper)
        } else if name.contains("parse") {
            Some(SemanticRoleKind::Parser)
        } else {
            None
        };
        if let (Some(role), Some(function)) = (role, function_for_address(program, symbol.address))
        {
            map.entry(function.function_id.clone())
                .or_default()
                .entry(role)
                .or_default()
                .insert(symbol.symbol_id.clone());
        }
    }
    map.into_iter()
        .map(|(function_id, evidence_by_role)| {
            let evidence_by_role = evidence_by_role
                .into_iter()
                .map(|(role, evidence)| (role, evidence.into_iter().collect()))
                .collect();
            (function_id, evidence_by_role)
        })
        .collect()
}

fn roles_for_string(string: &BinaryString) -> Vec<SemanticRoleKind> {
    let value = string.value.to_ascii_lowercase();
    let mut roles = Vec::new();
    if value.contains("/api/") || value.contains("http") || value.contains("route") {
        roles.push(SemanticRoleKind::HttpRoute);
    }
    if value.contains("login") || value.contains("auth") || value.contains("password") {
        roles.push(SemanticRoleKind::AuthCheck);
    }
    if value.contains("sqlite") || value.contains("select ") || value.contains("insert ") {
        roles.push(SemanticRoleKind::DatabaseAccess);
    }
    if value.contains("json") || value.contains("parse") {
        roles.push(SemanticRoleKind::Parser);
    }
    roles
}

fn role_for(
    function: &ThirFunction,
    role: SemanticRoleKind,
    confidence: f64,
    evidence: Vec<String>,
    authority: &str,
) -> SemanticRole {
    SemanticRole {
        role_id: format!(
            "semantic:role:{}",
            stable_hash(json!([&function.function_id, &role, &evidence]))
        ),
        function_id: function.function_id.clone(),
        role,
        confidence,
        evidence,
        authority: authority.to_string(),
    }
}

fn role_confidence(role: &SemanticRoleKind, evidence_count: usize) -> f64 {
    let base = match role {
        SemanticRoleKind::HttpRoute => 0.74,
        SemanticRoleKind::DatabaseAccess => 0.78,
        SemanticRoleKind::AuthCheck => 0.7,
        SemanticRoleKind::Parser => 0.66,
        SemanticRoleKind::CryptoWrapper => 0.72,
        SemanticRoleKind::Entrypoint => 0.72,
        SemanticRoleKind::Unknown => 0.3,
    };
    (base + (evidence_count.saturating_sub(1) as f64 * 0.03)).min(0.91)
}

fn is_entry_function(load: &BinaryLoadReport, function: &ThirFunction) -> bool {
    load.entrypoints
        .iter()
        .any(|entrypoint| entrypoint.address == function.address)
}

fn function_by_address(program: &ThirProgram, address: u64) -> Option<&ThirFunction> {
    program
        .functions
        .iter()
        .find(|function| function.address == address)
}

fn single_function_owner(program: &ThirProgram) -> Option<&ThirFunction> {
    (program.functions.len() == 1).then(|| &program.functions[0])
}

fn function_for_address(program: &ThirProgram, address: u64) -> Option<&ThirFunction> {
    if address == 0 {
        return None;
    }
    let mut functions = program.functions.iter().collect::<Vec<_>>();
    functions.sort_by_key(|function| function.address);
    for (index, function) in functions.iter().enumerate() {
        let next_address = functions
            .get(index + 1)
            .map(|next_function| next_function.address)
            .unwrap_or(u64::MAX);
        if address >= function.address && address < next_address {
            return Some(*function);
        }
    }
    None
}

fn component_name(function: &ThirFunction, roles: &[&SemanticRole]) -> String {
    roles
        .iter()
        .find(|role| role.role != SemanticRoleKind::Entrypoint)
        .map(|role| format!("{:?}Component", role.role))
        .or_else(|| function.name.clone())
        .unwrap_or_else(|| format!("Function_{:x}", function.address))
}

fn instruction_for_component(
    load: &BinaryLoadReport,
    component: &ComponentHypothesis,
    roles: &[&SemanticRole],
    signatures: &[&FunctionSemanticSignature],
    prototype_contracts: &[&FunctionPrototypeContract],
    data_type_contracts: &[&DataTypeContract],
    structure_field_access_contracts: &[&StructureFieldAccessContract],
    high_variable_contracts: &[&HighVariableContract],
    parameter_measure_contracts: &[&ParameterMeasureContract],
    pcode_inject_contracts: &[&PcodeInjectContract],
    flow_override_contracts: &[&FlowOverrideContract],
    variable_merge_contracts: &[&VariableMergeContract],
    decompiler_rule_contracts: &[&DecompilerRuleApplicationContract],
    jump_table_contracts: &[&JumpTableContract],
    equate_contracts: &[&EquateContract],
    external_linkage_contracts: &[&ExternalLinkageContract],
    program: &ThirProgram,
) -> ReconstructionInstruction {
    let mut requirements = roles
        .iter()
        .map(|role| Requirement::SemanticRole {
            role: role.role.clone(),
            summary: requirement_summary(&role.role),
        })
        .collect::<Vec<_>>();
    let branch_count = component
        .function_ids
        .iter()
        .filter_map(|function_id| {
            program
                .functions
                .iter()
                .find(|function| &function.function_id == function_id)
        })
        .flat_map(|function| function.blocks.iter())
        .flat_map(|block| block.statements.iter())
        .filter(|statement| matches!(statement, ThirStmt::Branch { .. }))
        .count();
    if branch_count > 0 {
        requirements.push(Requirement::BranchInvariant {
            condition: "Recovered branch structure must be preserved.".to_string(),
            then_behavior: "Follow the lifted branch target behavior.".to_string(),
            else_behavior: "Follow the lifted fallthrough behavior.".to_string(),
        });
    }
    for contract in prototype_contracts {
        requirements.push(Requirement::FunctionPrototype {
            function_id: contract
                .function_id
                .clone()
                .unwrap_or_else(|| format!("function:{:x}", contract.address)),
            prototype: contract.prototype.clone(),
            calling_convention: contract.calling_convention.clone(),
            return_type: contract.return_type.clone(),
            parameters: contract.parameters.clone(),
            has_varargs: contract.has_varargs,
            has_no_return: contract.has_no_return,
            evidence: prototype_contract_evidence_ids(contract),
        });
    }
    for contract in data_type_contracts {
        requirements.push(Requirement::DataTypeLayout {
            type_id: contract.type_id.clone(),
            name: contract.name.clone(),
            display_name: contract.display_name.clone(),
            kind: contract.kind.clone(),
            byte_len: contract.byte_len,
            component_count: contract.component_count,
            fields: contract.fields.clone(),
            hard_dependency_type_ids: contract.hard_dependency_type_ids.clone(),
            soft_dependency_type_ids: contract.soft_dependency_type_ids.clone(),
            evidence: data_type_contract_evidence_ids(contract),
        });
    }
    for contract in structure_field_access_contracts {
        requirements.push(Requirement::StructureFieldAccess {
            function_id: contract
                .function_id
                .clone()
                .unwrap_or_else(|| format!("function:{:x}", contract.address)),
            contract_id: contract.contract_id.clone(),
            access_kind: contract.access_kind.clone(),
            structure_type_id: contract.structure_type_id.clone(),
            structure_name: contract.structure_name.clone(),
            root_variable_id: contract.root_variable_id.clone(),
            root_variable_name: contract.root_variable_name.clone(),
            field_id: contract.field_id.clone(),
            field_name: contract.field_name.clone(),
            field_offset: contract.field_offset,
            field_byte_len: contract.field_byte_len,
            field_data_type: contract.field_data_type.clone(),
            pcode_opcode: contract.pcode_opcode.clone(),
            pcode_op_id: contract.pcode_op_id.clone(),
            statement_id: contract.statement_id.clone(),
            call_target_address: contract.call_target_address,
            call_input_slot: contract.call_input_slot,
            pointer_relative_type: contract.pointer_relative_type.clone(),
            recursive_call_depth: contract.recursive_call_depth,
            creates_new_structure: contract.creates_new_structure,
            extends_existing_structure: contract.extends_existing_structure,
            bit_offset: contract.bit_offset,
            bit_size: contract.bit_size,
            evidence: structure_field_access_evidence_ids(contract),
        });
    }
    for contract in high_variable_contracts {
        requirements.push(Requirement::HighVariableStorage {
            function_id: contract
                .function_id
                .clone()
                .unwrap_or_else(|| format!("function:{:x}", contract.address)),
            variable_id: contract.contract_id.clone(),
            name: contract.name.clone(),
            kind: contract.kind.clone(),
            data_type: contract.data_type.clone(),
            storage: contract.storage.clone(),
            first_use_address: contract.first_use_address,
            first_use_offset: contract.first_use_offset,
            instance_count: contract.instances.len(),
            name_locked: contract.name_locked,
            type_locked: contract.type_locked,
            dynamic_storage_required: contract.storage.dynamic_storage_required,
            evidence: high_variable_contract_evidence_ids(contract),
        });
    }
    for contract in parameter_measure_contracts {
        requirements.push(Requirement::ParameterMeasure {
            function_id: contract
                .function_id
                .clone()
                .unwrap_or_else(|| format!("function:{:x}", contract.address)),
            contract_id: contract.contract_id.clone(),
            io: contract.io.clone(),
            rank: contract.rank.clone(),
            rank_value: contract.rank_value,
            storage: contract.storage.clone(),
            data_type: contract.data_type.clone(),
            model_name: contract.model_name.clone(),
            extra_pop: contract.extra_pop,
            just_prototype: contract.just_prototype,
            base_variable_id: contract.base_variable_id.clone(),
            source_statement_id: contract.source_statement_id.clone(),
            num_calls: contract.num_calls,
            evidence: parameter_measure_contract_evidence_ids(contract),
        });
    }
    for contract in pcode_inject_contracts {
        requirements.push(Requirement::PcodeInjection {
            function_id: contract
                .function_id
                .clone()
                .unwrap_or_else(|| format!("function:{:x}", contract.address)),
            contract_id: contract.contract_id.clone(),
            kind: contract.kind.clone(),
            payload_name: contract.payload_name.clone(),
            payload_id: contract.payload_id,
            source: contract.source.clone(),
            target_name: contract.target_name.clone(),
            target_address: contract.target_address,
            userop_name: contract.userop_name.clone(),
            userop_index: contract.userop_index,
            param_shift: contract.param_shift,
            dynamic: contract.dynamic,
            incidental_copy: contract.incidental_copy,
            input_parameters: contract.input_parameters.clone(),
            output_parameters: contract.output_parameters.clone(),
            pcode_opcodes: contract.pcode_opcodes.clone(),
            body_hash: contract.body_hash.clone(),
            replaces_call: contract.replaces_call,
            falls_through: contract.falls_through,
            evidence: pcode_inject_contract_evidence_ids(contract),
        });
    }
    for contract in flow_override_contracts {
        requirements.push(Requirement::FlowOverride {
            function_id: contract
                .function_id
                .clone()
                .unwrap_or_else(|| format!("function:{:x}", contract.address)),
            contract_id: contract.contract_id.clone(),
            flow_override: contract.flow_override.clone(),
            reference_override: contract.reference_override.clone(),
            original_flow_type: contract.original_flow_type.clone(),
            modified_flow_type: contract.modified_flow_type.clone(),
            override_target_address: contract.override_target_address,
            fallthrough_address: contract.fallthrough_address,
            default_fallthrough_address: contract.default_fallthrough_address,
            primary_call_address: contract.primary_call_address,
            callsite_signature: contract.callsite_signature.clone(),
            calling_convention: contract.calling_convention.clone(),
            return_type: contract.return_type.clone(),
            parameters: contract.parameters.clone(),
            stack_delta_override: contract.stack_delta_override,
            override_namespace: contract.override_namespace.clone(),
            applied: contract.applied,
            evidence: flow_override_contract_evidence_ids(contract),
        });
    }
    for contract in variable_merge_contracts {
        requirements.push(Requirement::VariableMerge {
            function_id: contract
                .function_id
                .clone()
                .unwrap_or_else(|| format!("function:{:x}", contract.address)),
            contract_id: contract.contract_id.clone(),
            output_variable_id: contract.output_variable_id.clone(),
            input_variable_ids: contract.input_variable_ids.clone(),
            strategy: contract.strategy.clone(),
            forced: contract.forced,
            speculative: contract.speculative,
            merge_group: contract.merge_group,
            representative_instance_id: contract.representative_instance_id.clone(),
            cover_blocks: contract.cover_blocks.clone(),
            intersection_kind: contract.intersection_kind.clone(),
            intersecting_variable_ids: contract.intersecting_variable_ids.clone(),
            copy_trim_statement_ids: contract.copy_trim_statement_ids.clone(),
            phi_statement_ids: contract.phi_statement_ids.clone(),
            indirect_statement_ids: contract.indirect_statement_ids.clone(),
            preserves_split: contract.preserves_split,
            evidence: variable_merge_contract_evidence_ids(contract),
        });
    }
    for contract in decompiler_rule_contracts {
        requirements.push(Requirement::DecompilerRuleApplication {
            function_id: contract
                .function_id
                .clone()
                .unwrap_or_else(|| format!("function:{:x}", contract.address)),
            contract_id: contract.contract_id.clone(),
            action_name: contract.action_name.clone(),
            action_group: contract.action_group.clone(),
            action_path: contract.action_path.clone(),
            pool_name: contract.pool_name.clone(),
            rule_name: contract.rule_name.clone(),
            rule_group: contract.rule_group.clone(),
            opcodes: contract.opcodes.clone(),
            statement_id: contract.statement_id.clone(),
            before: contract.before.clone(),
            after: contract.after.clone(),
            effect_kind: contract.effect_kind.clone(),
            made_change: contract.made_change,
            repeat_iteration: contract.repeat_iteration,
            restart_requested: contract.restart_requested,
            evidence: decompiler_rule_contract_evidence_ids(contract),
        });
    }
    for contract in jump_table_contracts {
        requirements.push(Requirement::SwitchDispatch {
            function_id: contract
                .function_id
                .clone()
                .unwrap_or_else(|| format!("function:{:x}", contract.switch_address)),
            contract_id: contract.contract_id.clone(),
            switch_address: contract.switch_address,
            cases: contract.cases.clone(),
            load_tables: contract.load_tables.clone(),
            override_applied: contract.override_applied,
            references_complete: contract.references_complete,
            evidence: jump_table_contract_evidence_ids(contract),
        });
    }
    for contract in equate_contracts {
        requirements.push(Requirement::EquateConstant {
            function_id: contract
                .function_id
                .clone()
                .or_else(|| {
                    contract.references.iter().find_map(|reference| {
                        function_for_address(program, reference.address)
                            .map(|function| function.function_id.clone())
                    })
                })
                .unwrap_or_else(|| format!("function:equate:{:x}", contract.value)),
            contract_id: contract.contract_id.clone(),
            name: contract.name.clone(),
            display_name: contract.display_name.clone(),
            value: contract.value,
            display_value: contract.display_value.clone(),
            format: contract.format.clone(),
            enum_uuid: contract.enum_uuid.clone(),
            enum_based: contract.enum_based,
            valid_uuid: contract.valid_uuid,
            references: contract.references.clone(),
            evidence: equate_contract_evidence_ids(contract),
        });
    }
    for contract in external_linkage_contracts {
        requirements.push(Requirement::ExternalLinkage {
            function_id: contract
                .function_id
                .clone()
                .or_else(|| {
                    function_for_address(program, contract.local_address)
                        .map(|function| function.function_id.clone())
                })
                .unwrap_or_else(|| format!("function:external:{:x}", contract.local_address)),
            contract_id: contract.contract_id.clone(),
            local_address: contract.local_address,
            external_library: contract.external_library.clone(),
            external_library_path: contract.external_library_path.clone(),
            parent_namespace: contract.parent_namespace.clone(),
            external_label: contract.external_label.clone(),
            original_imported_name: contract.original_imported_name.clone(),
            external_address: contract.external_address,
            external_space_address: contract.external_space_address,
            source_type: contract.source_type.clone(),
            is_function: contract.is_function,
            data_type: contract.data_type.clone(),
            function_signature: contract.function_signature.clone(),
            thunk_chain: contract.thunk_chain.clone(),
            evidence: external_linkage_contract_evidence_ids(contract),
        });
    }
    let evidence = roles
        .iter()
        .flat_map(|role| role.evidence.iter().cloned())
        .chain(component.evidence.iter().cloned())
        .chain(
            prototype_contracts
                .iter()
                .flat_map(|contract| prototype_contract_evidence_ids(contract).into_iter()),
        )
        .chain(
            data_type_contracts
                .iter()
                .flat_map(|contract| data_type_contract_evidence_ids(contract).into_iter()),
        )
        .chain(
            high_variable_contracts
                .iter()
                .flat_map(|contract| high_variable_contract_evidence_ids(contract).into_iter()),
        )
        .chain(
            parameter_measure_contracts
                .iter()
                .flat_map(|contract| parameter_measure_contract_evidence_ids(contract).into_iter()),
        )
        .chain(
            pcode_inject_contracts
                .iter()
                .flat_map(|contract| pcode_inject_contract_evidence_ids(contract).into_iter()),
        )
        .chain(
            variable_merge_contracts
                .iter()
                .flat_map(|contract| variable_merge_contract_evidence_ids(contract).into_iter()),
        )
        .chain(
            decompiler_rule_contracts
                .iter()
                .flat_map(|contract| decompiler_rule_contract_evidence_ids(contract).into_iter()),
        )
        .chain(
            jump_table_contracts
                .iter()
                .flat_map(|contract| jump_table_contract_evidence_ids(contract).into_iter()),
        )
        .chain(
            equate_contracts
                .iter()
                .flat_map(|contract| equate_contract_evidence_ids(contract).into_iter()),
        )
        .chain(
            external_linkage_contracts
                .iter()
                .flat_map(|contract| external_linkage_contract_evidence_ids(contract).into_iter()),
        )
        .chain(
            signatures
                .iter()
                .map(|signature| signature.signature_id.clone()),
        )
        .chain(component.function_ids.iter().cloned())
        .collect::<BTreeSet<_>>()
        .into_iter()
        .collect::<Vec<_>>();
    if !evidence.is_empty() {
        requirements.push(Requirement::EvidenceTrace {
            evidence: evidence.clone(),
        });
    }
    let confidence = if roles.is_empty() {
        component.confidence
    } else {
        ((roles.iter().map(|role| role.confidence).sum::<f64>() / roles.len() as f64)
            + component.confidence)
            / 2.0
    };
    ReconstructionInstruction {
        id: format!(
            "recon:instr:{}",
            stable_hash(json!([
                &load.artifact.artifact_id,
                &component.component_id,
                &evidence
            ]))
        ),
        source_artifact: load.artifact.artifact_id.clone(),
        target: ReconstructionTarget {
            kind: "component".to_string(),
            id: component.component_id.clone(),
            language: "rust".to_string(),
            runtime: "axum".to_string(),
        },
        action: ReconstructionAction::ImplementComponent,
        requirements,
        validators: std::iter::once(ValidatorSpec::EvidencePresence {
            evidence: evidence.clone(),
        })
        .chain(std::iter::once(ValidatorSpec::BranchCoverage {
            branch_count,
        }))
        .chain(prototype_contracts.iter().map(|contract| {
            ValidatorSpec::PrototypeContract {
                function_id: contract
                    .function_id
                    .clone()
                    .unwrap_or_else(|| format!("function:{:x}", contract.address)),
                contract_id: contract.contract_id.clone(),
            }
        }))
        .chain(
            data_type_contracts
                .iter()
                .map(|contract| ValidatorSpec::DataTypeLayout {
                    type_id: contract.type_id.clone(),
                    contract_id: contract.contract_id.clone(),
                    layout_hash: data_type_layout_hash(contract),
                }),
        )
        .chain(structure_field_access_contracts.iter().map(|contract| {
            ValidatorSpec::StructureFieldAccess {
                function_id: contract
                    .function_id
                    .clone()
                    .unwrap_or_else(|| format!("function:{:x}", contract.address)),
                contract_id: contract.contract_id.clone(),
                access_hash: structure_field_access_hash(contract),
            }
        }))
        .chain(high_variable_contracts.iter().map(|contract| {
            ValidatorSpec::HighVariableStorage {
                function_id: contract
                    .function_id
                    .clone()
                    .unwrap_or_else(|| format!("function:{:x}", contract.address)),
                contract_id: contract.contract_id.clone(),
                storage_hash: high_variable_storage_hash(contract),
            }
        }))
        .chain(parameter_measure_contracts.iter().map(|contract| {
            ValidatorSpec::ParameterMeasure {
                function_id: contract
                    .function_id
                    .clone()
                    .unwrap_or_else(|| format!("function:{:x}", contract.address)),
                contract_id: contract.contract_id.clone(),
                measure_hash: parameter_measure_hash(contract),
            }
        }))
        .chain(pcode_inject_contracts.iter().map(|contract| {
            ValidatorSpec::PcodeInjection {
                function_id: contract
                    .function_id
                    .clone()
                    .unwrap_or_else(|| format!("function:{:x}", contract.address)),
                contract_id: contract.contract_id.clone(),
                payload_hash: pcode_inject_payload_hash(contract),
            }
        }))
        .chain(flow_override_contracts.iter().map(|contract| {
            ValidatorSpec::FlowOverride {
                function_id: contract
                    .function_id
                    .clone()
                    .unwrap_or_else(|| format!("function:{:x}", contract.address)),
                contract_id: contract.contract_id.clone(),
                override_hash: flow_override_hash(contract),
            }
        }))
        .chain(variable_merge_contracts.iter().map(|contract| {
            ValidatorSpec::VariableMerge {
                function_id: contract
                    .function_id
                    .clone()
                    .unwrap_or_else(|| format!("function:{:x}", contract.address)),
                contract_id: contract.contract_id.clone(),
                merge_hash: variable_merge_hash(contract),
            }
        }))
        .chain(decompiler_rule_contracts.iter().map(|contract| {
            ValidatorSpec::DecompilerRuleApplication {
                function_id: contract
                    .function_id
                    .clone()
                    .unwrap_or_else(|| format!("function:{:x}", contract.address)),
                contract_id: contract.contract_id.clone(),
                rule_hash: decompiler_rule_hash(contract),
            }
        }))
        .chain(jump_table_contracts.iter().map(|contract| {
            ValidatorSpec::SwitchDispatch {
                function_id: contract
                    .function_id
                    .clone()
                    .unwrap_or_else(|| format!("function:{:x}", contract.switch_address)),
                contract_id: contract.contract_id.clone(),
                dispatch_hash: jump_table_dispatch_hash(contract),
            }
        }))
        .chain(equate_contracts.iter().map(|contract| {
            ValidatorSpec::EquateConstant {
                function_id: contract
                    .function_id
                    .clone()
                    .or_else(|| {
                        contract.references.iter().find_map(|reference| {
                            function_for_address(program, reference.address)
                                .map(|function| function.function_id.clone())
                        })
                    })
                    .unwrap_or_else(|| format!("function:equate:{:x}", contract.value)),
                contract_id: contract.contract_id.clone(),
                value_hash: equate_value_hash(contract),
            }
        }))
        .chain(external_linkage_contracts.iter().map(|contract| {
            ValidatorSpec::ExternalLinkage {
                function_id: contract
                    .function_id
                    .clone()
                    .or_else(|| {
                        function_for_address(program, contract.local_address)
                            .map(|function| function.function_id.clone())
                    })
                    .unwrap_or_else(|| format!("function:external:{:x}", contract.local_address)),
                contract_id: contract.contract_id.clone(),
                linkage_hash: external_linkage_hash(contract),
            }
        }))
        .collect(),
        evidence,
        confidence,
        uncertainty: uncertainty_for_roles(roles),
    }
}

fn requirement_summary(role: &SemanticRoleKind) -> String {
    match role {
        SemanticRoleKind::Parser => "Implement equivalent input parsing behavior.".to_string(),
        SemanticRoleKind::AuthCheck => {
            "Preserve authorization and credential gate behavior.".to_string()
        }
        SemanticRoleKind::HttpRoute => {
            "Expose an equivalent route boundary and request/response contract.".to_string()
        }
        SemanticRoleKind::DatabaseAccess => {
            "Preserve database access and query preparation behavior.".to_string()
        }
        SemanticRoleKind::CryptoWrapper => {
            "Preserve cryptographic wrapper call boundaries and byte semantics.".to_string()
        }
        SemanticRoleKind::Entrypoint => "Preserve entrypoint reachability.".to_string(),
        SemanticRoleKind::Unknown => {
            "Preserve observed control-flow and data-flow behavior.".to_string()
        }
    }
}

fn uncertainty_for_roles(roles: &[&SemanticRole]) -> Vec<String> {
    let mut uncertainty = Vec::new();
    if roles.is_empty() {
        uncertainty.push(
            "Component has structural evidence but no semantic role evidence yet.".to_string(),
        );
    }
    for role in roles {
        if role.confidence < 0.75 {
            uncertainty.push(format!(
                "{:?} role is hypothesis-level and needs validation evidence.",
                role.role
            ));
        }
    }
    uncertainty
}

fn role_node(role: &SemanticRole, tenant_id: Option<&str>) -> NodeRecord {
    let node_id = graph_id(&role.role_id, tenant_id);
    NodeRecord::new(
        &node_id,
        [SEMANTIC_ROLE_LABEL],
        stamp_scoped_record(
            json!({
            "function_id": &role.function_id,
            "role": &role.role,
            "confidence": role.confidence,
            "evidence": &role.evidence,
            "authority": &role.authority,
            "source": RECONSTRUCT_SOURCE,
            "version": RECONSTRUCT_VERSION,
            }),
            &role.role_id,
            tenant_id,
        ),
    )
}

