    fn fixture_version_tracking_match() -> FunctionSemanticMatch {
        let source_function = semantic_function_in_artifact(
            "sha256:source",
            "thir:function:source:branch",
            vec![
                branch_statement("stmt:source:branch"),
                return_statement("stmt:source:return"),
            ],
        );
        let destination_function = semantic_function_in_artifact(
            "sha256:destination",
            "thir:function:destination:branch",
            vec![
                branch_statement("stmt:destination:branch"),
                return_statement("stmt:destination:return"),
            ],
        );
        let source_signature = function_semantic_signature(&source_function);
        let destination_signature = function_semantic_signature(&destination_function);
        let mut matches = match_function_semantic_signatures(
            std::slice::from_ref(&source_signature),
            std::slice::from_ref(&destination_signature),
            0.95,
        );
        assert_eq!(matches.len(), 1);
        matches.remove(0)
    }

