    #[test]
    fn semantic_signatures_are_stable_and_shape_aware() {
        let branch_function = semantic_function(
            "thir:function:branch",
            vec![
                branch_statement("stmt:branch"),
                return_statement("stmt:return"),
            ],
        );
        let same_branch_function = semantic_function(
            "thir:function:branch",
            vec![
                branch_statement("stmt:branch"),
                return_statement("stmt:return"),
            ],
        );
        let call_function = semantic_function(
            "thir:function:call",
            vec![
                call_statement("stmt:call", Some(0x2000)),
                return_statement("stmt:return"),
            ],
        );

        let branch_signature = function_semantic_signature(&branch_function);
        let same_branch_signature = function_semantic_signature(&same_branch_function);
        let call_signature = function_semantic_signature(&call_function);

        assert_eq!(branch_signature, same_branch_signature);
        assert_eq!(branch_signature.branch_count, 1);
        assert_eq!(call_signature.call_targets, vec![0x2000]);
        assert!(branch_signature
            .feature_hashes
            .windows(2)
            .all(|window| window[0] <= window[1]));

        let identical =
            compare_function_semantic_signatures(&branch_signature, &same_branch_signature);
        let different = compare_function_semantic_signatures(&branch_signature, &call_signature);

        assert!((identical.similarity - 1.0).abs() < 1e-12);
        assert!(different.similarity < identical.similarity);
        assert!(different.shared_feature_count < identical.shared_feature_count);
    }

    #[test]
