    #[test]
    fn function_hash_family_records_parent_and_child_context() {
        let caller = ThirFunction {
            function_id: "thir:function:caller".to_string(),
            artifact_id: "sha256:test".to_string(),
            address: 0x1000,
            name: None,
            confidence: 0.8,
            blocks: vec![ThirBasicBlock {
                block_id: "thir:block:caller".to_string(),
                function_id: "thir:function:caller".to_string(),
                address: 0x1000,
                statements: vec![
                    call_statement("stmt:caller:call", Some(0x2000)),
                    return_statement("stmt:caller:return"),
                ],
                successors: Vec::new(),
            }],
        };
        let callee = ThirFunction {
            function_id: "thir:function:callee".to_string(),
            artifact_id: "sha256:test".to_string(),
            address: 0x2000,
            name: None,
            confidence: 0.8,
            blocks: vec![ThirBasicBlock {
                block_id: "thir:block:callee".to_string(),
                function_id: "thir:function:callee".to_string(),
                address: 0x2000,
                statements: vec![return_statement("stmt:callee:return")],
                successors: Vec::new(),
            }],
        };
        let program = ThirProgram {
            artifact_id: "sha256:test".to_string(),
            functions: vec![caller, callee],
        };

        let signatures = compile_function_identifier_signatures(&program);
        let families = compile_function_hash_families(&program, &signatures);
        let caller_signature = signatures
            .iter()
            .find(|signature| signature.function_id == "thir:function:caller")
            .expect("caller signature");
        let callee_signature = signatures
            .iter()
            .find(|signature| signature.function_id == "thir:function:callee")
            .expect("callee signature");
        let caller_family = families
            .iter()
            .find(|family| family.function_id == "thir:function:caller")
            .expect("caller family");
        let callee_family = families
            .iter()
            .find(|family| family.function_id == "thir:function:callee")
            .expect("callee family");

        assert!(caller_family
            .child_signature_ids
            .contains(&callee_signature.signature_id));
        assert!(caller_family
            .child_full_hashes
            .contains(&callee_signature.full_hash));
        assert!(callee_family
            .parent_signature_ids
            .contains(&caller_signature.signature_id));
        assert!(callee_family
            .parent_full_hashes
            .contains(&caller_signature.full_hash));
    }

    #[test]
    fn reference_features_augment_signatures_and_hash_families() {
        let caller = semantic_function_at(
            "sha256:test",
            "thir:function:caller",
            0x1000,
            vec![return_statement("stmt:caller:return")],
        );
        let callee = semantic_function_at(
            "sha256:test",
            "thir:function:callee",
            0x2000,
            vec![return_statement("stmt:callee:return")],
        );
        let program = ThirProgram {
            artifact_id: "sha256:test".to_string(),
            functions: vec![caller, callee],
        };
        let references = vec![reference_feature("ghidra:ref:1001:2000", 0x1001, 0x2000)];

        let semantic_signatures =
            compile_function_semantic_signatures_with_reference_features(&program, &references);
        let caller_semantic_signature = semantic_signatures
            .iter()
            .find(|signature| signature.function_id == "thir:function:caller")
            .expect("caller semantic signature");
        assert_eq!(caller_semantic_signature.reference_count, 1);
        assert_eq!(caller_semantic_signature.reference_call_count, 1);
        assert_eq!(caller_semantic_signature.call_targets, vec![0x2000]);
        assert!(caller_semantic_signature
            .reference_feature_ids
            .contains(&"ghidra:ref:1001:2000".to_string()));
        assert!(caller_semantic_signature
            .evidence
            .contains(&"ghidra:ref:call".to_string()));

        let identifier_signatures =
            compile_function_identifier_signatures_with_reference_features(&program, &references);
        let families = compile_function_hash_families(&program, &identifier_signatures);
        let caller_identifier_signature = identifier_signatures
            .iter()
            .find(|signature| signature.function_id == "thir:function:caller")
            .expect("caller identifier signature");
        let callee_identifier_signature = identifier_signatures
            .iter()
            .find(|signature| signature.function_id == "thir:function:callee")
            .expect("callee identifier signature");
        let caller_family = families
            .iter()
            .find(|family| family.function_id == "thir:function:caller")
            .expect("caller family");
        assert_eq!(caller_identifier_signature.reference_call_count, 1);
        assert!(caller_identifier_signature
            .specific_tokens
            .iter()
            .any(|token| token == "reference_call_target:2000"));
        assert!(caller_family
            .child_signature_ids
            .contains(&callee_identifier_signature.signature_id));
    }

