    #[test]
    fn prototype_contracts_augment_signatures_and_obligations() {
        let load = fixture_load_report();
        let function_id = "thir:function:sha256:test:1000";
        let program = ThirProgram {
            artifact_id: "sha256:test".to_string(),
            functions: vec![thir_function(0x1000), thir_function(0x2000)],
        };
        let contracts = vec![prototype_contract(0x1000, Some(function_id))];

        let baseline = compile_reconstruction_analysis(&load, &program);
        let prototype_aware = compile_reconstruction_analysis_with_recovery_evidence(
            &load,
            &program,
            &[],
            &contracts,
        );
        let signature = prototype_aware
            .signatures
            .iter()
            .find(|signature| signature.function_id == function_id)
            .expect("prototype-aware signature");
        assert_eq!(prototype_aware.prototype_contracts.len(), 1);
        assert_eq!(signature.prototype_parameter_count, 2);
        assert!(signature.prototype_has_varargs);
        assert!(!signature.prototype_has_no_return);
        assert!(signature
            .prototype_contract_ids
            .contains(&"ghidra:prototype:login".to_string()));

        let identifier_signature = prototype_aware
            .identifier_signatures
            .iter()
            .find(|signature| signature.function_id == function_id)
            .expect("prototype-aware identifier signature");
        assert_eq!(identifier_signature.prototype_parameter_count, 2);
        assert!(identifier_signature
            .specific_tokens
            .iter()
            .any(|token| token.contains("prototype:param:0:user:char")));

        let baseline_component = baseline
            .components
            .iter()
            .find(|component| component.function_ids.contains(&function_id.to_string()))
            .expect("baseline component");
        let component = prototype_aware
            .components
            .iter()
            .find(|component| component.function_ids.contains(&function_id.to_string()))
            .expect("prototype component");
        assert!(component.confidence > baseline_component.confidence);
        assert!(component
            .evidence
            .contains(&"ghidra:prototype:login".to_string()));

        let instruction = prototype_aware
            .plan
            .instructions
            .iter()
            .find(|instruction| instruction.target.id == component.component_id)
            .expect("prototype instruction");
        assert!(instruction.requirements.iter().any(|requirement| matches!(
            requirement,
            Requirement::FunctionPrototype {
                prototype,
                has_varargs: true,
                ..
            } if prototype == "int login(char *user, int flags, ...)"
        )));
        assert!(instruction.validators.iter().any(|validator| matches!(
            validator,
            ValidatorSpec::PrototypeContract { contract_id, .. }
                if contract_id == "ghidra:prototype:login"
        )));
    }

    #[test]
    fn ghidra_oracle_function_prototype_facts_lower_to_contracts() {
        let load = fixture_load_report();
        let function_id = "thir:function:sha256:test:1000";
        let program = ThirProgram {
            artifact_id: "sha256:test".to_string(),
            functions: vec![thir_function(0x1000)],
        };
        let facts = ghidra_oracle_function_prototype_facts(function_id);

        let contracts = prototype_contracts_from_ghidra_oracle_facts(&load, &program, &facts);

        assert_eq!(contracts.len(), 1);
        let contract = &contracts[0];
        assert_eq!(contract.contract_id, "ghidra:prototype:login");
        assert_eq!(contract.function_id.as_deref(), Some(function_id));
        assert_eq!(contract.artifact_id, "sha256:test");
        assert_eq!(contract.address, 0x1000);
        assert_eq!(contract.name.as_deref(), Some("login"));
        assert_eq!(contract.prototype, "int login(char *user, int flags, ...)");
        assert_eq!(contract.calling_convention, "__stdcall");
        assert_eq!(contract.return_type.name, "int");
        assert_eq!(contract.return_type.kind, "primitive");
        assert_eq!(contract.return_type.byte_len, Some(4));
        assert_eq!(contract.return_storage, "register:EAX:4");
        assert_eq!(contract.return_storage_kind, PrototypeStorageKind::Register);
        assert_eq!(contract.parameters.len(), 2);
        assert_eq!(contract.parameters[0].ordinal, 0);
        assert_eq!(contract.parameters[0].name.as_deref(), Some("user"));
        assert_eq!(contract.parameters[0].data_type.name, "char *");
        assert_eq!(contract.parameters[0].data_type.kind, "pointer");
        assert_eq!(
            contract.parameters[0].storage_kind,
            PrototypeStorageKind::Register
        );
        assert_eq!(
            contract.parameters[0].comment.as_deref(),
            Some("username buffer")
        );
        assert_eq!(contract.parameters[1].name.as_deref(), Some("flags"));
        assert_eq!(
            contract.parameters[1].storage_kind,
            PrototypeStorageKind::Stack
        );
        assert!(contract.has_varargs);
        assert!(!contract.has_no_return);
        assert!(contract.has_custom_storage);
        assert_eq!(contract.stack_purge_size, Some(8));
        assert_eq!(contract.signature_source.as_deref(), Some("ANALYSIS"));
        assert!((contract.confidence - 0.9).abs() < f64::EPSILON);
        assert_eq!(contract.authority, "observed_fact");
        assert!(contract
            .evidence
            .contains(&"ghidra:prototype_evidence:login".to_string()));
        assert!(contract
            .evidence
            .contains(&"ghidra:prototype_param:login:user".to_string()));
        assert!(contract
            .evidence
            .contains(&"ghidra:datatype:/char_ptr".to_string()));
    }

