    #[test]
    fn data_type_dependency_plan_orders_hard_dependencies_and_trims_pointer_cycles() {
        let contracts = data_type_contracts();

        let plan = compile_data_type_dependency_plan("sha256:test", &contracts);

        let address_index = plan
            .ordered_type_ids
            .iter()
            .position(|type_id| type_id == "type:address")
            .expect("address in dependency order");
        let user_index = plan
            .ordered_type_ids
            .iter()
            .position(|type_id| type_id == "type:user")
            .expect("user in dependency order");
        assert!(address_index < user_index);
        assert!(plan.cycle_type_ids.is_empty());
        assert!(plan.hard_dependency_edges.iter().any(|edge| {
            edge.dependent_type_id == "type:user" && edge.dependency_type_id == "type:address"
        }));
        assert!(!plan.hard_dependency_edges.iter().any(|edge| {
            edge.dependent_type_id == "type:user_ptr" && edge.dependency_type_id == "type:user"
        }));
        assert!(plan.soft_dependency_edges.iter().any(|edge| {
            edge.dependent_type_id == "type:user_ptr" && edge.dependency_type_id == "type:user"
        }));
    }

