    #[test]
    fn writes_data_type_contract_nodes_and_dependency_edges_for_tenant() {
        let load = fixture_load_report();
        let function_id = "thir:function:sha256:test:1000";
        let program = ThirProgram {
            artifact_id: "sha256:test".to_string(),
            functions: vec![thir_function(0x1000)],
        };
        let prototypes = vec![user_pointer_prototype(0x1000, Some(function_id))];
        let data_types = data_type_contracts();
        let analysis = compile_reconstruction_analysis_with_data_type_contracts(
            &load,
            &program,
            &[],
            &prototypes,
            &data_types,
        );
        let mut store = InMemoryGraphStore::new();

        write_binary_facts_in_store(&mut store, &load).unwrap();
        write_thir_in_store(&mut store, &program).unwrap();
        store
            .upsert_node(NodeRecord::new(
                "ghidra:function:401000",
                ["GhidraOracleFunctionFact"],
                json!({}),
            ))
            .unwrap();
        for type_id in ["type:address", "type:user", "type:user_ptr"] {
            store
                .upsert_node(NodeRecord::new(
                    format!("ghidra:datatype_evidence:{type_id}"),
                    ["GhidraOracleDataTypeEvidence"],
                    json!({}),
                ))
                .unwrap();
        }
        write_reconstruction_analysis_in_store_for_tenant(&mut store, &analysis, "Travis-Gilbert")
            .unwrap();

        let contract_nodes = store.query_nodes(
            NodeQuery::label(DATA_TYPE_CONTRACT_LABEL)
                .with_property("tenant_id", json!("Travis-Gilbert")),
        );
        assert_eq!(contract_nodes.len(), 3);
        let plan_nodes = store.query_nodes(
            NodeQuery::label(DATA_TYPE_DEPENDENCY_PLAN_LABEL)
                .with_property("tenant_id", json!("Travis-Gilbert")),
        );
        assert_eq!(plan_nodes.len(), 1);
        let snapshot = store.snapshot();
        assert!(snapshot
            .edges
            .iter()
            .any(|edge| edge.edge_type == DATA_TYPE_DEPENDS_ON));
        assert!(snapshot
            .edges
            .iter()
            .any(|edge| edge.edge_type == DATA_TYPE_SOFT_DEPENDS_ON));
        assert!(snapshot
            .edges
            .iter()
            .any(|edge| edge.edge_type == PROTOTYPE_CONTRACT_USES_DATA_TYPE));
    }

