    #[test]
    fn call_stack_effects_lower_to_extra_pop_flow_overrides() {
        let load = fixture_load_report();
        let function_id = "thir:function:sha256:test:1000";
        let program = ThirProgram {
            artifact_id: "sha256:test".to_string(),
            functions: vec![semantic_function_at(
                "sha256:test",
                function_id,
                0x1000,
                vec![
                    callother_statement("stmt:stack_effect_call", 0x1010, "CALL sqlite3"),
                    callother_statement("stmt:after_stack_effect_call", 0x1014, "RETURN"),
                ],
            )],
        };
        let stack_effects = vec![call_stack_effect_contract(function_id)];

        let flow_overrides = flow_override_contracts_from_call_stack_effect_contracts(
            &load,
            &program,
            &stack_effects,
        );

        assert_eq!(flow_overrides.len(), 1);
        let contract = &flow_overrides[0];
        assert!(contract
            .contract_id
            .starts_with("ghidra:flow_override:extra_pop:"));
        assert_eq!(contract.function_id.as_deref(), Some(function_id));
        assert_eq!(contract.address, 0x1010);
        assert_eq!(contract.flow_override, FlowOverrideKind::Call);
        assert_eq!(
            contract.reference_override,
            Some(ReferenceOverrideKind::ExtraPop)
        );
        assert_eq!(contract.original_flow_type, "CALL");
        assert_eq!(contract.modified_flow_type, "EXTRA_POP_OVERRIDE");
        assert_eq!(contract.fallthrough_address, Some(0x1014));
        assert_eq!(contract.stack_delta_override, Some(24));
        assert_eq!(contract.calling_convention.as_deref(), Some("__stdcall"));
        assert!(contract.applied);
        assert!(contract
            .evidence
            .contains(&"ghidra:stack_effect:login:sqlite_prepare".to_string()));
        assert!(contract
            .evidence
            .contains(&"ghidra:stackptrflow:login:sqlite_prepare".to_string()));
    }

