    #[test]
    fn decompiler_diagnostics_flow_into_uncertainty_obligations() {
        let load = fixture_load_report();
        let function_id = "thir:function:sha256:test:1000";
        let program = ThirProgram {
            artifact_id: "sha256:test".to_string(),
            functions: vec![thir_function(0x1000)],
        };
        let diagnostics = vec![decompiler_diagnostic_contract(function_id)];

        let diagnostic_aware = compile_reconstruction_analysis_with_decompiler_diagnostic_contracts(
            &load,
            &program,
            &[],
            &[],
            &[],
            &[],
            &[],
            &[],
            &diagnostics,
        );

        assert_eq!(diagnostic_aware.decompiler_diagnostic_contracts.len(), 1);
        let component = &diagnostic_aware.components[0];
        assert!(component
            .evidence
            .contains(&"ghidra:decompiler_warning:login:flow:unimplemented".to_string()));
        let instruction = diagnostic_aware
            .plan
            .instructions
            .iter()
            .find(|instruction| instruction.target.id == component.component_id)
            .expect("diagnostic instruction");
        assert!(instruction.requirements.iter().any(|requirement| matches!(
            requirement,
            Requirement::DecompilerDiagnostic {
                address: Some(0x1014),
                category: DecompilerDiagnosticCategory::Flow,
                severity: DecompilerDiagnosticSeverity::Warning,
                placement: DecompilerDiagnosticPlacement::Header,
                message,
                source_pass,
                affects_control_flow: true,
                affects_prototype: false,
                affects_data_flow: false,
                remediation,
                ..
            } if message == "Control flow encountered unimplemented instructions"
                && source_pass.as_deref() == Some("FlowInfo::processInstruction")
                && remediation.as_deref().is_some_and(|text| text.contains("truncated-flow"))
        )));
        assert!(instruction.validators.iter().any(|validator| matches!(
            validator,
            ValidatorSpec::DecompilerDiagnostic { contract_id, .. }
                if contract_id == "ghidra:decompiler_warning:login:flow:unimplemented"
        )));
        assert!(instruction
            .uncertainty
            .iter()
            .any(|uncertainty| uncertainty.contains("unimplemented instructions")));
    }

