    #[test]
    fn compiler_spec_callfixups_lower_to_pcode_inject_contracts() {
        let compiler = compiler_spec_with_callfixup();
        let contracts =
            pcode_inject_contracts_from_program_compiler_specs("sha256:test", &[compiler]);

        assert_eq!(contracts.len(), 1);
        let contract = &contracts[0];
        assert!(contract.contract_id.starts_with("ghidra:callfixup:"));
        assert_eq!(contract.kind, PcodeInjectKind::CallFixup);
        assert_eq!(contract.payload_name, "x86_return_thunk");
        assert_eq!(contract.payload_id, Some(0));
        assert_eq!(contract.source, "x86-64-gcc.cspec");
        assert_eq!(contract.target_name.as_deref(), Some("__x86_return_thunk"));
        assert_eq!(contract.param_shift, 1);
        assert!(!contract.dynamic);
        assert!(contract.incidental_copy);
        assert!(contract.replaces_call);
        assert!(!contract.falls_through);
        assert_eq!(contract.body_hash, "body:sha256:return-thunk");
        assert_eq!(contract.input_parameters.len(), 1);
        assert_eq!(contract.input_parameters[0].name, "call_target");
        assert_eq!(contract.input_parameters[0].index, 0);
        assert_eq!(
            contract.input_parameters[0].direction,
            PcodeInjectParameterDirection::Input
        );
        assert_eq!(contract.output_parameters.len(), 1);
        assert_eq!(contract.output_parameters[0].name, "next_pc");
        assert_eq!(contract.output_parameters[0].index, 1);
        assert_eq!(
            contract.output_parameters[0].direction,
            PcodeInjectParameterDirection::Output
        );
        assert!(contract.pcode_opcodes.contains(&"LOAD".to_string()));
        assert!(contract.pcode_opcodes.contains(&"INT_ADD".to_string()));
        assert!(contract.pcode_opcodes.contains(&"RETURN".to_string()));
        assert!(contract
            .evidence
            .contains(&"program:language:test:compiler:gcc".to_string()));
    }

