    #[test]
    fn primary_reference_overrides_lower_to_flow_override_contracts() {
        let load = fixture_load_report();
        let function_id = "thir:function:sha256:test:1000";
        let program = ThirProgram {
            artifact_id: "sha256:test".to_string(),
            functions: vec![semantic_function_at(
                "sha256:test",
                function_id,
                0x1000,
                vec![
                    callother_statement("stmt:call_override", 0x1008, "CALLIND RAX"),
                    callother_statement("stmt:after_call_override", 0x100c, "COPY RAX, RBX"),
                    callother_statement("stmt:jump_override", 0x1010, "CBRANCH 0x5000, ZF"),
                    callother_statement("stmt:after_jump_override", 0x1014, "COPY RCX, RDX"),
                    callother_statement("stmt:callother_override", 0x1018, "CALLOTHER cpuid leaf"),
                    callother_statement("stmt:after_callother_override", 0x101c, "COPY R8, R9"),
                    callother_statement("stmt:fallthrough_override", 0x1020, "BRANCH 0x1030"),
                    callother_statement("stmt:default_fallthrough", 0x1024, "RETURN"),
                ],
            )],
        };
        let references = vec![
            reference_override_feature(
                "ghidra:ref:override:call",
                0x1008,
                0x4000,
                "CALL_OVERRIDE_UNCONDITIONAL",
                &["primary"],
            ),
            reference_override_feature(
                "ghidra:ref:override:jump",
                0x1010,
                0x5000,
                "JUMP_OVERRIDE_UNCONDITIONAL",
                &["primary"],
            ),
            reference_override_feature(
                "ghidra:ref:override:callother-call",
                0x1018,
                0x6000,
                "CALLOTHER_OVERRIDE_CALL",
                &["primary"],
            ),
            reference_override_feature(
                "ghidra:ref:override:callother-jump",
                0x1018,
                0x7000,
                "CALLOTHER_OVERRIDE_JUMP",
                &["primary"],
            ),
            reference_override_feature(
                "ghidra:ref:override:fallthrough",
                0x1020,
                0x1028,
                "FALL_THROUGH",
                &[],
            ),
        ];

        let contracts =
            flow_override_contracts_from_reference_override_features(&load, &program, &references);

        assert_eq!(contracts.len(), 4);
        let call_override = contracts
            .iter()
            .find(|contract| contract.address == 0x1008)
            .expect("call override contract");
        assert!(call_override
            .contract_id
            .starts_with("ghidra:flow_override:reference:"));
        assert_eq!(call_override.function_id.as_deref(), Some(function_id));
        assert_eq!(call_override.flow_override, FlowOverrideKind::Call);
        assert_eq!(
            call_override.reference_override,
            Some(ReferenceOverrideKind::CallOverride)
        );
        assert_eq!(call_override.override_target_address, Some(0x4000));
        assert_eq!(call_override.primary_call_address, Some(0x4000));
        assert_eq!(call_override.fallthrough_address, Some(0x100c));
        assert_eq!(call_override.modified_flow_type, "UNCONDITIONAL_CALL");
        assert!(call_override.applied);

        let jump_override = contracts
            .iter()
            .find(|contract| contract.address == 0x1010)
            .expect("jump override contract");
        assert_eq!(jump_override.flow_override, FlowOverrideKind::Branch);
        assert_eq!(
            jump_override.reference_override,
            Some(ReferenceOverrideKind::JumpOverride)
        );
        assert_eq!(jump_override.override_target_address, Some(0x5000));
        assert_eq!(jump_override.fallthrough_address, None);
        assert_eq!(jump_override.modified_flow_type, "UNCONDITIONAL_JUMP");

        let callother_override = contracts
            .iter()
            .find(|contract| contract.address == 0x1018)
            .expect("callother override contract");
        assert_eq!(callother_override.flow_override, FlowOverrideKind::Call);
        assert_eq!(
            callother_override.reference_override,
            Some(ReferenceOverrideKind::CallOtherOverrideCall)
        );
        assert_eq!(callother_override.override_target_address, Some(0x6000));
        assert_eq!(callother_override.primary_call_address, Some(0x6000));
        assert_eq!(callother_override.modified_flow_type, "CALL");
        assert!(!contracts.iter().any(|contract| {
            contract.address == 0x1018
                && contract.reference_override == Some(ReferenceOverrideKind::CallOtherOverrideJump)
        }));

        let fallthrough_override = contracts
            .iter()
            .find(|contract| contract.address == 0x1020)
            .expect("fallthrough override contract");
        assert_eq!(fallthrough_override.flow_override, FlowOverrideKind::None);
        assert_eq!(
            fallthrough_override.reference_override,
            Some(ReferenceOverrideKind::Fallthrough)
        );
        assert_eq!(fallthrough_override.override_target_address, None);
        assert_eq!(fallthrough_override.fallthrough_address, Some(0x1028));
        assert_eq!(
            fallthrough_override.default_fallthrough_address,
            Some(0x1024)
        );
        assert_eq!(fallthrough_override.modified_flow_type, "FALL_THROUGH");
    }

