    #[test]
    fn ghidra_oracle_semantic_signatures_lower_to_matching_signatures() {
        let load = fixture_load_report();
        let fixture = ghidra_oracle_fixture();
        let source = ghidra_oracle_semantic_signature(
            "ghidra:function:login",
            "0x1000",
            "login",
            vec!["0x0000002a", "0xdeadbeef", "0x00000064"],
            vec!["0x2000"],
        );
        let destination = ghidra_oracle_semantic_signature(
            "ghidra:function:login_clone",
            "0x3000",
            "login_clone_uncertain",
            vec!["0x0000002a", "0xdeadbeef", "0x00000065"],
            vec!["0x2000"],
        );
        let signatures = function_semantic_signatures_from_ghidra_oracle_semantic_signatures(
            &load.artifact.artifact_id,
            Some(&fixture),
            &[source.clone(), destination.clone()],
        );

        assert_eq!(signatures.len(), 2);
        let source_signature = signatures
            .iter()
            .find(|signature| signature.function_id == "ghidra:function:login")
            .expect("source signature lowers");
        let destination_signature = signatures
            .iter()
            .find(|signature| signature.function_id == "ghidra:function:login_clone")
            .expect("destination signature lowers");
        assert_eq!(
            source_signature.feature_version,
            "ghidra-bsim-signature-v0:settings:7:decompiler:11.4"
        );
        assert!(source_signature
            .feature_hashes
            .contains(&"ghidra-bsim:0xdeadbeef".to_string()));
        assert!(source_signature
            .feature_hashes
            .contains(&"ghidra-bsim-debug:varnode:0xdeadbeef".to_string()));
        assert_eq!(source_signature.call_targets, vec![0x2000]);
        assert_eq!(source_signature.authority, "observed_fact");
        assert!(source_signature
            .evidence
            .contains(&"ghidra:fixture:symz3:login".to_string()));
        assert!(destination_signature
            .quality_flags
            .contains(&SignatureQualityFlag::HasUnimplementedInstructions));

        let matches = match_function_semantic_signatures(
            std::slice::from_ref(source_signature),
            std::slice::from_ref(destination_signature),
            0.5,
        );
        assert_eq!(matches.len(), 1);
        assert!(matches[0].similarity > 0.5);

        let mut store = InMemoryGraphStore::new();
        store
            .upsert_node(NodeRecord::new(
                "ghidra:function:login",
                ["GhidraOracleFunctionFact"],
                json!({"logical_id": "ghidra:function:login"}),
            ))
            .expect("source function node writes");
        store
            .upsert_node(NodeRecord::new(
                "ghidra:function:login_clone",
                ["GhidraOracleFunctionFact"],
                json!({"logical_id": "ghidra:function:login_clone"}),
            ))
            .expect("destination function node writes");
        for evidence_id in signatures
            .iter()
            .flat_map(|signature| signature.evidence.iter())
            .collect::<BTreeSet<_>>()
        {
            let graph_evidence_id = evidence_graph_id(evidence_id, Some("Travis-Gilbert"));
            store
                .upsert_node(NodeRecord::new(
                    &graph_evidence_id,
                    ["GhidraOracleSignatureEvidence"],
                    json!({"logical_id": evidence_id}),
                ))
                .expect("signature evidence node writes");
        }
        write_function_semantic_signatures_in_store_for_tenant(
            &mut store,
            &signatures,
            "Travis-Gilbert",
        )
        .expect("Ghidra semantic signatures write through reconstruction graph");
        assert_eq!(
            store
                .query_nodes(NodeQuery::label(FUNCTION_SEMANTIC_SIGNATURE_LABEL))
                .len(),
            2
        );
    }

