    #[test]
    fn writes_pcode_execution_contract_nodes_for_tenant() {
        let load = fixture_load_report();
        let function_id = "thir:function:sha256:test:1000";
        let program = ThirProgram {
            artifact_id: "sha256:test".to_string(),
            functions: vec![thir_function(0x1000)],
        };
        let pcode_executions = vec![pcode_execution_contract(function_id)];
        let analysis = compile_reconstruction_analysis_with_pcode_execution_contracts(
            &load,
            &program,
            &[],
            &[],
            &[],
            &[],
            &[],
            &[],
            &[],
            &pcode_executions,
        );
        let mut store = InMemoryGraphStore::new();

        write_binary_facts_in_store(&mut store, &load).unwrap();
        write_thir_in_store(&mut store, &program).unwrap();
        let contract = &analysis.pcode_execution_contracts[0];
        let owned_evidence = std::iter::once(contract.contract_id.clone())
            .chain(
                contract
                    .initial_observations
                    .iter()
                    .chain(contract.final_observations.iter())
                    .map(|observation| observation.observation_id.clone()),
            )
            .chain(contract.taint_flows.iter().map(|flow| flow.flow_id.clone()))
            .chain(
                contract
                    .symbolic_preconditions
                    .iter()
                    .map(|precondition| precondition.precondition_id.clone()),
            )
            .chain(
                contract
                    .symbolic_values
                    .iter()
                    .map(|value| value.value_id.clone()),
            )
            .chain(contract.symbolic_state.iter().flat_map(|state| {
                std::iter::once(state.summary_id.clone()).chain(
                    state
                        .memory_witnesses
                        .iter()
                        .map(|witness| witness.witness_id.clone()),
                )
            }))
            .collect::<BTreeSet<_>>();
        for evidence_id in pcode_execution_contract_evidence_ids(contract) {
            if owned_evidence.contains(&evidence_id) {
                continue;
            }
            store
                .upsert_node(NodeRecord::new(
                    tenant_scoped_reconstruction_id("Travis-Gilbert", &evidence_id),
                    ["GhidraOraclePcodeExecutionEvidence"],
                    json!({
                        "tenant_id": "Travis-Gilbert",
                        "original_id": evidence_id,
                    }),
                ))
                .unwrap();
        }
        write_reconstruction_analysis_in_store_for_tenant(&mut store, &analysis, "Travis-Gilbert")
            .unwrap();

        let contract_nodes = store.query_nodes(
            NodeQuery::label(PCODE_EXECUTION_CONTRACT_LABEL)
                .with_property("tenant_id", json!("Travis-Gilbert")),
        );
        assert_eq!(contract_nodes.len(), 1);
        assert_eq!(
            contract_nodes[0].properties["domain"],
            json!(PcodeExecutionDomain::PairedConcreteTaint)
        );
        assert_eq!(
            contract_nodes[0].properties["execution_hash"].as_str(),
            Some("exec:login:valid_user:v1")
        );
        assert_eq!(
            contract_nodes[0].properties["solver_status"],
            json!(PcodeSolverStatus::Satisfiable)
        );
        assert_eq!(
            contract_nodes[0].properties["symbolic_precondition_count"],
            json!(1)
        );
        assert!(contract_nodes[0].properties["symbolic_state_hash"]
            .as_str()
            .is_some());
        let observation_nodes = store.query_nodes(
            NodeQuery::label(PCODE_EXECUTION_OBSERVATION_LABEL)
                .with_property("tenant_id", json!("Travis-Gilbert")),
        );
        assert_eq!(observation_nodes.len(), 3);
        let taint_nodes = store.query_nodes(
            NodeQuery::label(PCODE_TAINT_FLOW_LABEL)
                .with_property("tenant_id", json!("Travis-Gilbert")),
        );
        assert_eq!(taint_nodes.len(), 1);
        let precondition_nodes = store.query_nodes(
            NodeQuery::label(PCODE_SYMBOLIC_PRECONDITION_LABEL)
                .with_property("tenant_id", json!("Travis-Gilbert")),
        );
        assert_eq!(precondition_nodes.len(), 1);
        let symbolic_value_nodes = store.query_nodes(
            NodeQuery::label(PCODE_SYMBOLIC_VALUE_LABEL)
                .with_property("tenant_id", json!("Travis-Gilbert")),
        );
        assert_eq!(symbolic_value_nodes.len(), 1);
        let state_nodes = store.query_nodes(
            NodeQuery::label(PCODE_SYMBOLIC_STATE_SUMMARY_LABEL)
                .with_property("tenant_id", json!("Travis-Gilbert")),
        );
        assert_eq!(state_nodes.len(), 1);
        assert_eq!(state_nodes[0].properties["memory_witness_count"], json!(2));
        let memory_witness_nodes = store.query_nodes(
            NodeQuery::label(PCODE_MEMORY_WITNESS_LABEL)
                .with_property("tenant_id", json!("Travis-Gilbert")),
        );
        assert_eq!(memory_witness_nodes.len(), 2);
        let snapshot = store.snapshot();
        assert!(snapshot
            .edges
            .iter()
            .any(|edge| edge.edge_type == FUNCTION_HAS_PCODE_EXECUTION_CONTRACT));
        assert!(snapshot
            .edges
            .iter()
            .any(|edge| edge.edge_type == PCODE_EXECUTION_HAS_OBSERVATION));
        assert!(snapshot
            .edges
            .iter()
            .any(|edge| edge.edge_type == PCODE_EXECUTION_HAS_TAINT_FLOW));
        assert!(snapshot
            .edges
            .iter()
            .any(|edge| edge.edge_type == PCODE_EXECUTION_HAS_PRECONDITION));
        assert!(snapshot
            .edges
            .iter()
            .any(|edge| edge.edge_type == PCODE_EXECUTION_HAS_SYMBOLIC_STATE));
        assert!(snapshot
            .edges
            .iter()
            .any(|edge| edge.edge_type == PCODE_EXECUTION_HAS_SYMBOLIC_VALUE));
        assert!(snapshot
            .edges
            .iter()
            .any(|edge| edge.edge_type == PCODE_SYMBOLIC_STATE_HAS_MEMORY_WITNESS));
    }

    #[test]
    fn pcode_execution_validator_accepts_replay_receipts() {
        let function_id = "thir:function:sha256:test:1000";
        let load = fixture_load_report();
        let program = ThirProgram {
            artifact_id: "sha256:test".to_string(),
            functions: vec![thir_function(0x1000)],
        };
        let normalized = normalize_pcode_execution_contracts(
            &load,
            &program,
            &[pcode_execution_contract(function_id)],
        );
        let contract = normalized.first().expect("normalized execution contract");
        let execution_hash = pcode_execution_hash(contract);
        let instruction = ReconstructionInstruction {
            id: "recon:instr:pcode_execution".to_string(),
            source_artifact: "sha256:test".to_string(),
            target: ReconstructionTarget {
                kind: "function".to_string(),
                id: function_id.to_string(),
                language: "rust".to_string(),
                runtime: "axum".to_string(),
            },
            action: ReconstructionAction::ImplementFunction,
            requirements: Vec::new(),
            validators: vec![
                ValidatorSpec::PcodeExecution {
                    function_id: function_id.to_string(),
                    contract_id: contract.contract_id.clone(),
                    execution_hash: execution_hash.clone(),
                },
                ValidatorSpec::PcodeSymbolicPreconditions {
                    function_id: function_id.to_string(),
                    contract_id: contract.contract_id.clone(),
                    precondition_hash: pcode_symbolic_precondition_hash(contract),
                },
                ValidatorSpec::PcodeSymbolicState {
                    function_id: function_id.to_string(),
                    contract_id: contract.contract_id.clone(),
                    state_hash: pcode_symbolic_state_hash(contract),
                },
            ],
            evidence: vec![contract.contract_id.clone()],
            confidence: 0.92,
            uncertainty: Vec::new(),
        };
        let precondition_hash = pcode_symbolic_precondition_hash(contract);
        let state_hash = pcode_symbolic_state_hash(contract);

        let receipt = validate_instruction(
            &instruction,
            json!({
                "pcode_execution": {
                    "function_id": function_id,
                    "contract_id": "ghidra:pcode_execution:login:valid_user",
                    "execution_hash": execution_hash,
                },
                "pcode_symbolic_preconditions": {
                    "function_id": function_id,
                    "contract_id": "ghidra:pcode_execution:login:valid_user",
                    "precondition_hash": precondition_hash,
                },
                "pcode_symbolic_state": {
                    "function_id": function_id,
                    "contract_id": "ghidra:pcode_execution:login:valid_user",
                    "state_hash": state_hash,
                },
            }),
        );
        assert!(receipt.passed);

        let wrong = validate_instruction(
            &instruction,
            json!({
                "function_id": function_id,
                "contract_id": "ghidra:pcode_execution:login:other",
                "execution_hash": "wrong",
            }),
        );
        assert!(!wrong.passed);
    }

    #[test]
    fn flow_override_contracts_flow_into_reconstruction_obligations() {
        let load = fixture_load_report();
        let function_id = "thir:function:sha256:test:1000";
        let program = ThirProgram {
            artifact_id: "sha256:test".to_string(),
            functions: vec![thir_function(0x1000)],
        };
        let prototypes = vec![user_pointer_prototype(0x1000, Some(function_id))];
        let data_types = data_type_contracts();
        let high_variables = high_variable_contracts(function_id);
        let parameter_measures = vec![parameter_measure_contract(function_id)];
        let pcode_injects = vec![pcode_inject_contract(function_id)];
        let flow_overrides = vec![flow_override_contract(function_id)];

        let baseline = compile_reconstruction_analysis_with_pcode_inject_contracts(
            &load,
            &program,
            &[],
            &prototypes,
            &data_types,
            &[],
            &high_variables,
            &parameter_measures,
            &pcode_injects,
        );
        let override_aware = compile_reconstruction_analysis_with_flow_override_contracts(
            &load,
            &program,
            &[],
            &prototypes,
            &data_types,
            &[],
            &high_variables,
            &parameter_measures,
            &pcode_injects,
            &flow_overrides,
        );

        assert_eq!(override_aware.flow_override_contracts.len(), 1);
        let baseline_component = &baseline.components[0];
        let component = &override_aware.components[0];
        assert!(component.confidence > baseline_component.confidence);
        assert!(component
            .evidence
            .contains(&"ghidra:flow_override:login:call_as_return".to_string()));
        let instruction = override_aware
            .plan
            .instructions
            .iter()
            .find(|instruction| instruction.target.id == component.component_id)
            .expect("flow-override instruction");
        assert!(instruction.requirements.iter().any(|requirement| matches!(
            requirement,
            Requirement::FlowOverride {
                flow_override: FlowOverrideKind::CallReturn,
                reference_override: Some(ReferenceOverrideKind::CallOverride),
                original_flow_type,
                modified_flow_type,
                override_target_address: Some(0x401080),
                fallthrough_address: Some(0x1010),
                default_fallthrough_address: Some(0x1014),
                callsite_signature,
                calling_convention,
                stack_delta_override: Some(16),
                applied: true,
                parameters,
                ..
            } if original_flow_type == "UNCONDITIONAL_CALL"
                && modified_flow_type == "CALL_TERMINATOR"
                && callsite_signature.as_deref() == Some("int login_override(char *user)")
                && calling_convention.as_deref() == Some("__stdcall")
                && parameters.len() == 1
        )));
        assert!(instruction.validators.iter().any(|validator| matches!(
            validator,
            ValidatorSpec::FlowOverride { contract_id, .. }
                if contract_id == "ghidra:flow_override:login:call_as_return"
        )));
    }

