    #[test]
    fn jump_table_override_symbols_lower_to_contracts() {
        let load = fixture_load_report();
        let function_id = "thir:function:sha256:test:1000";
        let program = ThirProgram {
            artifact_id: "sha256:test".to_string(),
            functions: vec![thir_function(0x1000)],
        };
        let symbols = jump_table_override_symbols(function_id);

        let contracts = jump_table_contracts_from_override_symbols(&load, &program, &symbols);

        assert_eq!(contracts.len(), 1);
        let contract = &contracts[0];
        assert!(contract
            .contract_id
            .starts_with("ghidra:jumptable_override:"));
        assert_eq!(contract.function_id.as_deref(), Some(function_id));
        assert_eq!(contract.artifact_id, "sha256:test");
        assert_eq!(contract.switch_address, 0x1004);
        assert_eq!(contract.display_format.as_deref(), Some("hex"));
        assert!(contract.override_applied);
        assert!(contract.references_complete);
        assert_eq!(contract.cases.len(), 2);
        assert!(contract.cases.iter().any(|case| {
            case.label_value == Some(0)
                && case.target_address == 0x1010
                && case.label.as_deref() == Some("case_0")
        }));
        assert!(contract.cases.iter().any(|case| {
            case.label_value == Some(1)
                && case.target_address == 0x1020
                && case.label.as_deref() == Some("case_1")
        }));
        assert!(contract
            .evidence
            .contains(&"override::jmp_0x1004".to_string()));
        assert!(contract
            .evidence
            .iter()
            .any(|evidence| evidence.starts_with("ghidra:jumptable_override_evidence:")));
        assert!(contract
            .evidence
            .iter()
            .any(|evidence| { evidence == "ghidra:symbol:override::jmp_0x1004:switch" }));
    }

